1	"use client";
2	
3	import { useState, useEffect, useCallback, useRef } from "react";
4	import styles from "@/app/styles/table.module.css";
5	
6	// ── Tipler ──────────────────────────────────────────────────────
7	interface NumuneItem {
8	  ID: number;
9	  Evrak_No: string;
10	  RaporNo: string;
11	  Numune_Adi: string;
12	  Grup: string | null;
13	  Tur: string | null;
14	}
15	
16	interface EvrakGroup {
17	  evrakNo: string;
18	  tarih: string | null;
19	  firmaAd: string | null;
20	  projeAd: string | null;
21	  numuneSayisi: number;
22	  odemeDurumu: string | null;
23	  numuneler: NumuneItem[];
24	}
25	
26	const EMPTY_NUMUNE = {
27	  Tarih: new Date().toISOString().split("T")[0],
28	  Evrak_No: "", RaporNo: "", Firma_ID: "", Numune_Adi: "", Grup: "",
29	};
30	
31	// Fatura kesilmiş = yalnızca bu iki durum; diğerleri (null dahil) → Faturalandır aktif
32	const isFaturali = (d: string | null) => d === "Ödendi" || d === "Bekliyor";
33	
34	// ── Yardımcı bileşenler ──────────────────────────────────────────
35	function OdemeBadge({ durum }: { durum: string | null }) {
36	  if (!durum) return <span style={{ color: "var(--color-text-tertiary)", fontSize: "0.78rem" }}>—</span>;
37	  const map: Record<string, { bg: string; fg: string }> = {
38	    "Ödendi":   { bg: "#34c75918", fg: "#248a3d" },
39	    "Bekliyor": { bg: "#ff950018", fg: "#c06800" },
40	  };
41	  const c = map[durum] ?? { bg: "#8e8e9318", fg: "#636366" };
42	  return (
43	    <span style={{
44	      display: "inline-block", padding: "2px 9px", borderRadius: 10,
45	      fontSize: "0.72rem", fontWeight: 600, background: c.bg, color: c.fg,
46	    }}>{durum}</span>
47	  );
48	}
49	
50	function NumuneBadge({ count }: { count: number }) {
51	  return (
52	    <span style={{
53	      display: "inline-flex", alignItems: "center", gap: 3,
54	      padding: "2px 8px", borderRadius: 10, fontSize: "0.72rem", fontWeight: 600,
55	      background: "var(--color-accent-light)", color: "var(--color-accent)",
56	    }}>
57	      {count}
58	    </span>
59	  );
60	}
61	
62	// ── Ana bileşen ─────────────────────────────────────────────────
63	export default function NumuneKabulTable() {
64	  const [groups, setGroups]         = useState<EvrakGroup[]>([]);
65	  const [total, setTotal]           = useState(0);
66	  const [page, setPage]             = useState(1);
67	  const [limit, setLimit]           = useState(20);
68	  const [totalPages, setTotalPages] = useState(1);
69	  const [search, setSearch]         = useState("");
70	  const [loading, setLoading]       = useState(true);
71	  const [transitioning, setTransitioning] = useState(false); // sayfa geçişi (skeleton değil, overlay)
72	  const [error, setError]           = useState("");
73	
74	  // Accordion
75	  const [openGroups, setOpenGroups] = useState<Set<string>>(new Set());
76	
77	  // Modal
78	  const [editRow, setEditRow]     = useState<typeof EMPTY_NUMUNE & { ID?: number } | null>(null);
79	  const [isNew, setIsNew]         = useState(false);
80	  const [saving, setSaving]       = useState(false);
81	  const [formError, setFormError] = useState("");
82	  const [deleteId, setDeleteId]   = useState<number | null>(null);
83	  const [deleting, setDeleting]   = useState(false);
84	
85	  const searchTimer = useRef<ReturnType<typeof setTimeout> | null>(null);
86	  const abortRef    = useRef<AbortController | null>(null);
87	  const latestReqId = useRef(0); // monotone artan — yalnızca son istek geçerli
88	  const didMount    = useRef(false); // sayfa/limit effect'i mount'ta çalışmasın
89	
90	  // ── Veri çekme ──────────────────────────────────────────────
91	  const fetchData = useCallback(async (
92	    p: number, s: string, l: number,
93	    opts: { clearFirst?: boolean } = {}
94	  ) => {
95	    // Her çağrıya benzersiz ID ver; yalnızca en son ID'li yanıt işlenir
96	    const reqId = ++latestReqId.current;
97	
98	    if (abortRef.current) abortRef.current.abort();
99	    const ctrl = new AbortController();
100	    abortRef.current = ctrl;
101	
102	    if (opts.clearFirst) {
103	      // Arama: eski grupları temizle + skeleton göster
104	      setGroups([]);
105	      setLoading(true);
106	      setTransitioning(false);
107	    } else {
108	      // Sayfa/limit geçişi: eski grupları koru, hafif overlay
109	      setTransitioning(true);
110	      setLoading(false);
111	    }
112	    setError("");
113	
114	    try {
115	      const res = await fetch(
116	        `/api/numune-kabul?page=${p}&limit=${l}&search=${encodeURIComponent(s)}`,
117	        { signal: ctrl.signal }
118	      );
119	
120	      // Eski istek tamamlandıysa yoksay
121	      if (reqId !== latestReqId.current) return;
122	
123	      if (!res.ok) throw new Error((await res.json()).error || "Hata");
124	      const json = await res.json();
125	
126	      setGroups(json.data);
127	      setTotal(json.total);
128	      setTotalPages(json.totalPages);
129	    } catch (e: any) {
130	      if (e.name === "AbortError" || reqId !== latestReqId.current) return;
131	      setError(e.message);
132	    } finally {
133	      if (reqId === latestReqId.current) {
134	        setLoading(false);
135	        setTransitioning(false);
136	      }
137	    }
138	  }, []);
139	
140	  // İlk yükleme — bir kez çalışır
141	  useEffect(() => {
142	    fetchData(1, "", limit, { clearFirst: true });
143	  }, []);
144	
145	  // Sayfa / limit değişimi — mount sonrası her değişimde çalışır
146	  useEffect(() => {
147	    if (!didMount.current) { didMount.current = true; return; }
148	    fetchData(page, search, limit, { clearFirst: false });
149	  }, [page, limit]);
150	
151	  const handleSearch = (val: string) => {
152	    setSearch(val);
153	    if (searchTimer.current) clearTimeout(searchTimer.current);
154	    searchTimer.current = setTimeout(() => {
155	      setPage(1);
156	      fetchData(1, val, limit, { clearFirst: true });
157	    }, 200);
158	  };
159	
160	  // ── Accordion ───────────────────────────────────────────────
161	  const toggleGroup = (evrakNo: string) => {
162	    setOpenGroups(prev => {
163	      const next = new Set(prev);
164	      next.has(evrakNo) ? next.delete(evrakNo) : next.add(evrakNo);
165	      return next;
166	    });
167	  };
168	
169	  // ── CRUD ────────────────────────────────────────────────────
170	  const handleSave = async () => {
171	    if (!editRow) return;
172	    setSaving(true); setFormError("");
173	    try {
174	      const url    = isNew ? "/api/numune-kabul" : `/api/numune-kabul/${editRow.ID}`;
175	      const method = isNew ? "POST" : "PUT";
176	      const res    = await fetch(url, {
177	        method, headers: { "Content-Type": "application/json" },
178	        body: JSON.stringify(editRow),
179	      });
180	      if (!res.ok) throw new Error((await res.json()).error || "Kayıt hatası");
181	      setEditRow(null);
182	      fetchData(page, search, limit, { clearFirst: false });
183	    } catch (e: any) { setFormError(e.message); }
184	    finally { setSaving(false); }
185	  };
186	
187	  const handleDelete = async () => {
188	    if (!deleteId) return;
189	    setDeleting(true);
190	    try {
191	      const res = await fetch(`/api/numune-kabul/${deleteId}`, { method: "DELETE" });
192	      if (!res.ok) throw new Error((await res.json()).error || "Silinemedi");
193	      setDeleteId(null);
194	      fetchData(page, search, limit, { clearFirst: false });
195	    } catch (e: any) { setError(e.message); }
196	    finally { setDeleting(false); }
197	  };
198	
199	  const openNew = () => { setIsNew(true); setFormError(""); setEditRow({ ...EMPTY_NUMUNE }); };
200	  const openEdit = (n: NumuneItem) => {
201	    setIsNew(false); setFormError("");
202	    setEditRow({
203	      ID: n.ID, Tarih: "", Evrak_No: n.Evrak_No, RaporNo: n.RaporNo,
204	      Firma_ID: "", Numune_Adi: n.Numune_Adi, Grup: n.Grup || "",
205	    });
206	  };
207	  const closeEdit = () => setEditRow(null);
208	
209	  // ── Sayfalama ────────────────────────────────────────────────
210	  const goTo = (p: number) => { if (p >= 1 && p <= totalPages) setPage(p); };
211	  const pageNums = () => {
212	    const nums: (number | "…")[] = [];
213	    if (totalPages <= 7) { for (let i = 1; i <= totalPages; i++) nums.push(i); }
214	    else {
215	      nums.push(1);
216	      if (page > 3) nums.push("…");
217	      for (let i = Math.max(2, page - 1); i <= Math.min(totalPages - 1, page + 1); i++) nums.push(i);
218	      if (page < totalPages - 2) nums.push("…");
219	      nums.push(totalPages);
220	    }
221	    return nums;
222	  };
223	
224	  const formatTarih = (t: string | null) => {
225	    if (!t) return "—";
226	    const [y, m, d] = t.split("-");
227	    return `${d}.${m}.${y}`;
228	  };
229	
230	  // ── Render ───────────────────────────────────────────────────
231	  return (
232	    <>
233	      {/* ── Toolbar ── */}
234	      <div className={styles.toolbar}>
235	        <div className={styles.toolbarLeft}>
236	          <div className={styles.searchBox} style={{ width: 340 }}>
237	            <svg className={styles.searchIcon} viewBox="0 0 20 20" fill="currentColor" width="15" height="15">
238	              <path fillRule="evenodd" d="M9 3.5a5.5 5.5 0 1 0 0 11 5.5 5.5 0 0 0 0-11ZM2 9a7 7 0 1 1 12.452 4.391l3.328 3.329a.75.75 0 1 1-1.06 1.06l-3.329-3.328A7 7 0 0 1 2 9Z" clipRule="evenodd" />
239	            </svg>
240	            <input
241	              className={styles.searchInput}
242	              placeholder="Evrak no, rapor no, firma, numune adı…"
243	              value={search}
244	              onChange={e => handleSearch(e.target.value)}
245	            />
246	            {search && (
247	              <button className={styles.searchClear} onClick={() => handleSearch("")}>
248	                <svg viewBox="0 0 20 20" fill="currentColor" width="14" height="14">
249	                  <path d="M6.28 5.22a.75.75 0 0 0-1.06 1.06L8.94 10l-3.72 3.72a.75.75 0 1 0 1.06 1.06L10 11.06l3.72 3.72a.75.75 0 1 0 1.06-1.06L11.06 10l3.72-3.72a.75.75 0 0 0-1.06-1.06L10 8.94 6.28 5.22Z" />
250	                </svg>
251	              </button>
252	            )}
253	          </div>
254	          <span className={styles.totalCount}>{total} evrak</span>
255	        </div>
256	        <div className={styles.toolbarRight}>
257	          <select className={styles.pageSizeSelect} value={limit}
258	            onChange={e => { setLimit(Number(e.target.value)); setPage(1); }}>
259	            {[10, 20, 50].map(n => <option key={n} value={n}>{n} / sayfa</option>)}
260	          </select>
261	          <button className={styles.addBtn} onClick={openNew}>
262	            <svg viewBox="0 0 20 20" fill="currentColor" width="15" height="15">
263	              <path d="M10.75 4.75a.75.75 0 0 0-1.5 0v4.5h-4.5a.75.75 0 0 0 0 1.5h4.5v4.5a.75.75 0 0 0 1.5 0v-4.5h4.5a.75.75 0 0 0 0-1.5h-4.5v-4.5Z" />
264	            </svg>
265	            Yeni Numune
266	          </button>
267	        </div>
268	      </div>
269	
270	      {/* ── Accordion listesi ── */}
271	      <div
272	        className={styles.tableCard}
273	        style={{ position: "relative", opacity: transitioning ? 0.55 : 1, transition: "opacity 0.15s" }}
274	      >
275	        {error && <div className={styles.errorBar}>{error}</div>}
276	
277	        {/* ── Kolon başlıkları ── */}
278	        <div style={{
279	          display: "flex", alignItems: "center", gap: 0,
280	          padding: "8px 16px",
281	          borderBottom: "1px solid var(--color-border-light)",
282	          background: "var(--color-surface)",
283	        }}>
284	          <div style={{ width: 24 }} /> {/* chevron */}
285	          <div style={{ width: 88,  fontSize: "0.7rem", fontWeight: 600, textTransform: "uppercase", letterSpacing: "0.06em", color: "var(--color-text-tertiary)" }}>Tarih</div>
286	          <div style={{ width: 130, fontSize: "0.7rem", fontWeight: 600, textTransform: "uppercase", letterSpacing: "0.06em", color: "var(--color-text-tertiary)" }}>Evrak No</div>
287	          <div style={{ flex: 1,    fontSize: "0.7rem", fontWeight: 600, textTransform: "uppercase", letterSpacing: "0.06em", color: "var(--color-text-tertiary)" }}>Firma / Proje</div>
288	          <div style={{ width: 64,  fontSize: "0.7rem", fontWeight: 600, textTransform: "uppercase", letterSpacing: "0.06em", color: "var(--color-text-tertiary)", textAlign: "center" }}>Numune</div>
289	          <div style={{ width: 136,  fontSize: "0.7rem", fontWeight: 600, textTransform: "uppercase", letterSpacing: "0.06em", color: "var(--color-text-tertiary)", textAlign: "center" }}>Ödeme</div>
290	          <div style={{ width: 36,  fontSize: "0.7rem", fontWeight: 600, textTransform: "uppercase", letterSpacing: "0.06em", color: "var(--color-text-tertiary)", textAlign: "center" }}>Fatura</div>
291	        </div>
292	
293	        {/* Skeleton */}
294	        {loading && (
295	          <div style={{ padding: "6px 0" }}>
296	            {Array.from({ length: 6 }).map((_, i) => (
297	              <div key={i} style={{
298	                display: "flex", alignItems: "center", gap: 12,
299	                padding: "14px 20px",
300	                borderBottom: "1px solid var(--color-border-light)",
301	              }}>
302	                <span className={styles.skeleton} style={{ width: 14, height: 14, borderRadius: 3 }} />
303	                <span className={styles.skeleton} style={{ width: 80 }} />
304	                <span className={styles.skeleton} style={{ width: 110 }} />
305	                <span className={styles.skeleton} style={{ flex: 1 }} />
306	                <span className={styles.skeleton} style={{ width: 60 }} />
307	                <span className={styles.skeleton} style={{ width: 70 }} />
308	                <span className={styles.skeleton} style={{ width: 28, height: 28, borderRadius: 6 }} />
309	              </div>
310	            ))}
311	          </div>
312	        )}
313	
314	        {/* Boş */}
315	        {!loading && groups.length === 0 && (
316	          <div className={styles.empty}>
317	            <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5" width="36" height="36">
318	              <path strokeLinecap="round" strokeLinejoin="round" d="M9.75 9.75l4.5 4.5m0-4.5l-4.5 4.5M21 12a9 9 0 1 1-18 0 9 9 0 0 1 18 0Z" />
319	            </svg>
320	            Kayıt bulunamadı
321	          </div>
322	        )}
323	
324	        {/* Accordion grupları */}
325	        {!loading && groups.map((group, gi) => {
326	          const isOpen = openGroups.has(group.evrakNo);
327	          return (
328	            <div
329	              key={group.evrakNo}
330	              style={{ borderBottom: gi < groups.length - 1 ? "1px solid var(--color-border-light)" : "none" }}
331	            >
332	              {/* ── Grup başlık satırı ── */}
333	              <div
334	                style={{
335	                  display: "flex", alignItems: "center", gap: 0,
336	                  padding: "12px 16px",
337	                  cursor: "pointer",
338	                  background: isOpen ? "var(--color-surface-2)" : "transparent",
339	                  transition: "background 0.12s",
340	                  userSelect: "none",
341	                }}
342	                onClick={() => toggleGroup(group.evrakNo)}
343	              >
344	                {/* Chevron */}
345	                <div style={{ width: 24, flexShrink: 0, display: "flex", alignItems: "center" }}>
346	                  <svg
347	                    viewBox="0 0 20 20" fill="currentColor" width="14" height="14"
348	                    style={{
349	                      color: "var(--color-text-tertiary)",
350	                      transform: isOpen ? "rotate(90deg)" : "rotate(0deg)",
351	                      transition: "transform 0.18s ease",
352	                    }}
353	                  >
354	                    <path fillRule="evenodd" d="M7.21 14.77a.75.75 0 0 1 .02-1.06L11.168 10 7.23 6.29a.75.75 0 1 1 1.04-1.08l4.5 4.25a.75.75 0 0 1 0 1.08l-4.5 4.25a.75.75 0 0 1-1.06-.02Z" clipRule="evenodd" />
355	                  </svg>
356	                </div>
357	
358	                {/* Tarih */}
359	                <div style={{ width: 88, flexShrink: 0, fontSize: "0.8rem", color: "var(--color-text-secondary)", fontVariantNumeric: "tabular-nums" }}>
360	                  {formatTarih(group.tarih)}
361	                </div>
362	
363	                {/* Evrak No */}
364	                <div style={{ width: 130, flexShrink: 0, fontWeight: 700, fontSize: "0.845rem", color: "var(--color-text-primary)", fontVariantNumeric: "tabular-nums" }}>
365	                  {group.evrakNo}
366	                </div>
367	
368	                {/* Firma / Proje */}
369	                <div style={{ flex: 1, minWidth: 0, overflow: "hidden" }}>
370	                  <div style={{
371	                    fontWeight: 500, fontSize: "0.845rem", color: "var(--color-text-primary)",
372	                    whiteSpace: "nowrap", overflow: "hidden", textOverflow: "ellipsis",
373	                  }}>{group.firmaAd ?? "—"}</div>
374	                  {group.projeAd && (
375	                    <div style={{
376	                      fontSize: "0.77rem", color: "var(--color-text-tertiary)",
377	                      whiteSpace: "nowrap", overflow: "hidden", textOverflow: "ellipsis",
378	                    }}>{group.projeAd}</div>
379	                  )}
380	                </div>
381	
382	                {/* Numune sayısı */}
383	                <div style={{ width: 64, display: "flex", justifyContent: "center" }}>
384	                  <NumuneBadge count={group.numuneSayisi} />
385	                </div>
386	
387	                {/* Ödeme */}
388	                <div style={{ width: 136, display: "flex", justifyContent: "center" }}>
389	                  <OdemeBadge durum={group.odemeDurumu} />
390	                </div>
391	
392	                {/* Faturalandır — icon-only */}
393	                <div
394	                  style={{ width: 36, display: "flex", justifyContent: "flex-end" }}
395	                  onClick={e => e.stopPropagation()}
396	                >
397	                  <button
398	                    className={styles.editBtn}
399	                    disabled={isFaturali(group.odemeDurumu)}
400	                    title={isFaturali(group.odemeDurumu) ? "Fatura kesilmiş" : "Faturalandır"}
401	                    onClick={() => {
402	                      // TODO: router.push(`/musteriler/proforma-listesi?evrakNo=${group.evrakNo}`)
403	                    }}
404	                    style={isFaturali(group.odemeDurumu)
405	                      ? { opacity: 0.25, cursor: "not-allowed" }
406	                      : { color: "#248a3d", borderColor: "#34c75940" }
407	                    }
408	                  >
409	                    <svg viewBox="0 0 20 20" fill="currentColor" width="13" height="13">
410	                      <path fillRule="evenodd" d="M4 4a2 2 0 0 0-2 2v8a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2V6a2 2 0 0 0-2-2H4Zm0 2h12v8H4V6Zm3 5a1 1 0 0 1 1-1h4a1 1 0 1 1 0 2H8a1 1 0 0 1-1-1Zm1-3a1 1 0 0 0 0 2h2a1 1 0 0 0 0-2H8Z" clipRule="evenodd" />
411	                    </svg>
412	                  </button>
413	                </div>
414	              </div>
415	
416	              {/* ── Açılır numune listesi ── */}
417	              {isOpen && (
418	                <div style={{ background: "var(--color-surface-2)", borderTop: "1px solid var(--color-border-light)" }}>
419	                  {group.numuneler.length === 0 ? (
420	                    <div style={{ padding: "12px 20px 12px 52px", fontSize: "0.8rem", color: "var(--color-text-tertiary)" }}>
421	                      Numune bulunamadı.
422	                    </div>
423	                  ) : (
424	                    <table style={{ width: "100%", borderCollapse: "collapse", fontSize: "0.82rem", tableLayout: "fixed" }}>
425	                      <colgroup>
426	                        <col style={{ width: 160 }} />
427	                        <col />
428	                        <col style={{ width: 160 }} />
429	                        <col style={{ width: 72 }} />
430	                      </colgroup>
431	                      <thead>
432	                        <tr style={{
433	                          background: "var(--color-surface)",
434	                          borderBottom: "2px solid var(--color-border)",
435	                        }}>
436	                          {["Rapor No", "Numune Adı", "Grup / Tür", ""].map((h, i) => (
437	                            <th key={i} style={{
438	                              padding: i === 0 ? "6px 12px 6px 52px" : "6px 12px",
439	                              textAlign: "left", fontWeight: 700,
440	                              fontSize: "0.68rem", textTransform: "uppercase", letterSpacing: "0.07em",
441	                              color: "var(--color-text-secondary)",
442	                              whiteSpace: "nowrap",
443	                            }}>{h}</th>
444	                          ))}
445	                        </tr>
446	                      </thead>
447	                      <tbody>
448	                        {group.numuneler.map((n, ni) => (
449	                          <tr
450	                            key={n.ID}
451	                            style={{
452	                              borderBottom: ni < group.numuneler.length - 1
453	                                ? "1px solid var(--color-border-light)"
454	                                : "none",
455	                            }}
456	                          >
457	                            <td style={{
458	                              padding: "9px 12px 9px 52px",
459	                              fontWeight: 600, color: "var(--color-accent)",
460	                              fontVariantNumeric: "tabular-nums", whiteSpace: "nowrap",
461	                            }}>
462	                              {n.RaporNo}
463	                            </td>
464	                            <td style={{ padding: "9px 12px", color: "var(--color-text-primary)", fontWeight: 500 }}>
465	                              {n.Numune_Adi}
466	                            </td>
467	                            <td style={{ padding: "9px 12px", color: "var(--color-text-secondary)" }}>
468	                              {[n.Grup, n.Tur].filter(Boolean).join(" / ") || "—"}
469	                            </td>
470	                            <td style={{ padding: "9px 12px", whiteSpace: "nowrap" }}>
471	                              <div className={styles.actionBtns}>
472	                                <button className={styles.editBtn} title="Düzenle" onClick={() => openEdit(n)}>
