508	                    className={`${styles.pageBtn} ${page === n ? styles.pageBtnActive : ""}`}
509	                    disabled={transitioning}
510	                    onClick={() => goTo(n as number)}
511	                  >{n}</button>
512	            )}
513	            <button className={styles.pageBtn} onClick={() => goTo(page + 1)} disabled={page === totalPages || transitioning}>›</button>
514	            <span className={styles.pageInfo}>{total} evrak</span>
