523	            <div className={styles.modalHeader}>
524	              <h2>{isNew ? "Yeni Numune" : `Düzenle — ${editRow.RaporNo || editRow.Evrak_No}`}</h2>
525	              <button className={styles.modalClose} onClick={closeEdit}>
526	                <svg viewBox="0 0 20 20" fill="currentColor" width="14" height="14">
527	                  <path d="M6.28 5.22a.75.75 0 0 0-1.06 1.06L8.94 10l-3.72 3.72a.75.75 0 1 0 1.06 1.06L10 11.06l3.72 3.72a.75.75 0 1 0 1.06-1.06L11.06 10l3.72-3.72a.75.75 0 0 0-1.06-1.06L10 8.94 6.28 5.22Z" />
528	                </svg>
529	              </button>
530	            </div>
531	            <div className={styles.modalBody}>
532	              {formError && <div className={styles.formError}>{formError}</div>}
533	              <div className={styles.formGroup} style={{ marginBottom: 14 }}>
534	                <label>Tarih</label>
535	                <input type="date" value={editRow.Tarih || ""}
536	                  onChange={e => setEditRow(p => p && ({ ...p, Tarih: e.target.value }))} />
537	              </div>
