545	                  <label>Rapor No <span className={styles.required}>*</span></label>
546	                  <input value={editRow.RaporNo || ""}
547	                    onChange={e => setEditRow(p => p && ({ ...p, RaporNo: e.target.value }))} />
548	                </div>
549	              </div>
