551	                <label>Numune Adı <span className={styles.required}>*</span></label>
552	                <input value={editRow.Numune_Adi || ""}
553	                  onChange={e => setEditRow(p => p && ({ ...p, Numune_Adi: e.target.value }))} />
554	              </div>
555	              <div className={styles.formGrid} style={{ marginBottom: 14 }}>
556	                <div className={styles.formGroup}>
557	                  <label>Firma ID</label>
558	                  <input type="number" min={1} placeholder="Firma ID"
559	                    value={editRow.Firma_ID || ""}
560	                    onChange={e => setEditRow(p => p && ({ ...p, Firma_ID: e.target.value }))} />
561	                </div>
