563	                  <label>Grup</label>
564	                  <input value={editRow.Grup || ""}
565	                    onChange={e => setEditRow(p => p && ({ ...p, Grup: e.target.value }))} />
566	                </div>
567	              </div>
568	            </div>
569	            <div className={styles.modalFooter}>
570	              <button className={styles.cancelBtn} onClick={closeEdit} disabled={saving}>İptal</button>
571	              <button className={styles.saveBtn} onClick={handleSave} disabled={saving}>
572	                {saving ? <span className={styles.loader} /> : isNew ? "Kaydet" : "Güncelle"}
573	              </button>
574	            </div>
575	          </div>
576	        </div>
577	      )}
578	
579	      {/* ── PASİFE AL ONAY ── */}
580	      {deleteId !== null && (
581	        <div className={styles.modalOverlay} onClick={() => setDeleteId(null)}>
582	          <div className={styles.modal} style={{ maxWidth: 380 }} onClick={e => e.stopPropagation()}>
583	            <div className={styles.modalHeader}>
584	              <h2>Pasife Al</h2>
585	              <button className={styles.modalClose} onClick={() => setDeleteId(null)}>
586	                <svg viewBox="0 0 20 20" fill="currentColor" width="14" height="14">
587	                  <path d="M6.28 5.22a.75.75 0 0 0-1.06 1.06L8.94 10l-3.72 3.72a.75.75 0 1 0 1.06 1.06L10 11.06l3.72 3.72a.75.75 0 1 0 1.06-1.06L11.06 10l3.72-3.72a.75.75 0 0 0-1.06-1.06L10 8.94 6.28 5.22Z" />
588	                </svg>
589	              </button>
