146	    if (!RaporNo?.trim())    return Response.json({ error: "Rapor No zorunludur."   }, { status: 400 });
147	    if (!Numune_Adi?.trim()) return Response.json({ error: "Numune Adı zorunludur." }, { status: 400 });
148	
149	    const pool = await poolPromise;
150	    const result = await pool.request()
151	      .input("Tarih",      Tarih      || null)
152	      .input("Evrak_No",   Evrak_No.trim())
153	      .input("RaporNo",    RaporNo.trim())
154	      .input("Firma_ID",   Firma_ID ? parseInt(Firma_ID) : null)
155	      .input("Numune_Adi", Numune_Adi.trim())
156	      .input("Grup",       Grup       || null)
157	      .query(`
158	        INSERT INTO NKR (Tarih, Evrak_No, RaporNo, Firma_ID, Numune_Adi, Grup, Durum)
159	        OUTPUT INSERTED.ID
160	        VALUES (@Tarih, @Evrak_No, @RaporNo, @Firma_ID, @Numune_Adi, @Grup, 'Aktif')
161	      `);
162	
163	    return Response.json({ id: result.recordset[0].ID }, { status: 201 });
164	  } catch (e: any) {
