6	// ----------------------------------------------------------------
7	// GET  /api/hizmetler?search=&page=1&limit=20
8	// ----------------------------------------------------------------
9	export async function GET(request: NextRequest) {
10	  const session = await getServerSession(authOptions);
11	  if (!session) return Response.json({ error: "Yetkisiz erişim" }, { status: 401 });
12	
13	  const sp = request.nextUrl.searchParams;
14	  const search = sp.get("search")?.trim() || "";
15	  const page   = Math.max(1, parseInt(sp.get("page")  || "1",  10));
16	  const limit  = Math.min(100, Math.max(5, parseInt(sp.get("limit") || "20", 10)));
17	  const offset = (page - 1) * limit;
18	
19	  try {
20	    const pool = await poolPromise;
21	
22	    const whereClauses: string[] = ["Durumu = 'Aktif'"];
23	
24	    if (search) {
25	      whereClauses.push(`(
26	        Ad       LIKE N'%' + @search + '%'
27	        OR AdEn  LIKE N'%' + @search + '%'
28	        OR Kod   LIKE N'%' + @search + '%'
29	        OR Method LIKE N'%' + @search + '%'
30	        OR Matriks LIKE N'%' + @search + '%'
31	      )`);
32	    }
33	
34	    const where = `WHERE ${whereClauses.join(" AND ")}`;
35	
36	    const req = pool.request()
