      .input("Karar",            nkr.Karar            || null)
      .input("Dil",              nkr.Dil              || null)
      .input("Firma_ID",         nkr.Firma_ID         ? parseInt(nkr.Firma_ID)  : null)
      .input("Aciklama",         nkr.Aciklama         || null)
      .input("Numune_Adi",       nkr.Numune_Adi.trim())
      .input("Numune_Adi_En",    nkr.Numune_Adi_En    || null)
      .input("Urun_Tipi",        nkr.Urun_Tipi        || null)
      .input("UGDTip_ID",        nkr.UGDTip_ID        ? parseInt(nkr.UGDTip_ID) : null)
      .input("Hedef_Grup",       nkr.Hedef_Grup       || null)
      .input("TesteMiktar",      nkr.TesteMiktar      ? parseFloat(nkr.TesteMiktar)     : null)
      .input("TesteMiktarBirim", nkr.TesteMiktarBirim || null)
      .query(`
