  // rUGDTip seçildiğinde uygulama alanı + A değeri otomatik gelir
  const selectedTip = lookup.rUGDTipler.find(t => t.ID === form.UGDTip_ID);
  const kategoriler  = [...new Set(lookup.rUGDTipler.map(t => t.Kategori))].sort();
  const tiplerForKat = form.UGDTip_Kategori
    ? lookup.rUGDTipler.filter(t => t.Kategori === form.UGDTip_Kategori)
    : [];

  // Grup değişince Tur sıfırla
  const handleGrup = (val: string) => onChange({ Grup: val, Tur: "" });
  const turler = form.Grup
    ? lookup.grupTurleri.filter(g => g.Grup === form.Grup).map(g => g.Tur)
    : [];

  const handleFotoFile = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    onChange({ FotoFile: file, FotoPreview: URL.createObjectURL(file) });
  };

  const handleWebcapture = (dataUrl: string) => {
    setWC(false);
    // Base64 → File
    const arr  = dataUrl.split(",");
    const mime = arr[0].match(/:(.*?);/)![1];
    const bstr = atob(arr[1]);
    let n = bstr.length;
    const u8 = new Uint8Array(n);
    while (n--) u8[n] = bstr.charCodeAt(n);
    const file = new File([u8], "webcam.jpg", { type: mime });
    onChange({ FotoFile: file, FotoPreview: dataUrl });
  };

  // ── Bölüm başlığı helper ─────────────────────────────────
