      borderBottom: "1px solid var(--color-border-light)",
      paddingBottom: 8, marginBottom: 14, marginTop: 24,
    }}>
      {title}
    </div>
  );

  const inp: React.CSSProperties = { width: "100%" };

  return (
    <div style={{ padding: "20px 24px" }}>

      {/* ── KAYIT BİLGİLERİ ── */}
