            onChange={e => onChange({ Teklif_No: e.target.value })} />
        </div>
        <div className={styles.formGroup}>
          <label>Talep No</label>
          <input style={inp} value={form.Talep_No}
            onChange={e => onChange({ Talep_No: e.target.value })} />
        </div>
      </div>

      <div className={styles.formGrid3} style={{ marginBottom: 14 }}>
        <div className={styles.formGroup}>
          <label>
            Evrak No <span className={styles.required}>*</span>
            {loadingNos && <span style={{ marginLeft: 4, color: "var(--color-text-tertiary)", fontSize: "0.7rem" }}>…</span>}
          </label>
          <input style={inp} value={form.Evrak_No}
            onChange={e => onChange({ Evrak_No: e.target.value })} />
        </div>
        <div className={styles.formGroup}>
          <label>
            Rapor No <span className={styles.required}>*</span>
            {loadingNos && <span style={{ marginLeft: 4, color: "var(--color-text-tertiary)", fontSize: "0.7rem" }}>…</span>}
          </label>
          <input style={inp} value={form.RaporNo}
            onChange={e => onChange({ RaporNo: e.target.value })} />
        </div>
        <div className={styles.formGroup}>
          <label>Revizyon No</label>
          <input type="number" min={0} style={inp} value={form.Revno}
            onChange={e => onChange({ Revno: e.target.value })} />
        </div>
      </div>

      <div className={styles.formGrid3} style={{ marginBottom: 14 }}>
        <div className={styles.formGroup}>
          <label>Barkod</label>
          <input style={inp} value={form.Barkod}
            onChange={e => onChange({ Barkod: e.target.value })} />
        </div>
        <div className={styles.formGroup}>
          <label>Ürün Grubu</label>
          <select style={inp} value={form.Grup} onChange={e => handleGrup(e.target.value)}>
            <option value="">— Seçin —</option>
            {GRUPLAR.map(g => <option key={g} value={g}>{g}</option>)}
          </select>
        </div>
        <div className={styles.formGroup}>
          <label>Ürün Türü</label>
          <select style={inp} value={form.Tur} onChange={e => onChange({ Tur: e.target.value })}
            disabled={!form.Grup}>
