          <label>Karar Kuralı</label>
          <select style={inp} value={form.Karar} onChange={e => onChange({ Karar: e.target.value })}>
            <option value="">— Seçin —</option>
            {KARALAR.map(k => <option key={k} value={k}>{k}</option>)}
          </select>
        </div>
        <div className={styles.formGroup}>
