      </div>

      <div className={styles.formGrid3} style={{ marginBottom: 14 }}>
        {/* Miktar + Birim */}
        <div className={styles.formGroup}>
          <label>Miktar</label>
          <div style={{ display: "flex", gap: 6 }}>
            <input type="number" min={0} placeholder="0"
              style={{ flex: 1 }} value={form.Miktar}
              onChange={e => onChange({ Miktar: e.target.value })} />
            <select style={{ width: 72 }} value={form.Birim}
              onChange={e => onChange({ Birim: e.target.value })}>
              <option value="">—</option>
              {BIRIMLER.map(b => <option key={b} value={b}>{b}</option>)}
            </select>
          </div>
        </div>
        {/* Teste Gelen Miktar */}
        <div className={styles.formGroup}>
          <label>Teste Gelen Miktar</label>
          <div style={{ display: "flex", gap: 6 }}>
            <input type="number" min={0} placeholder="0"
              style={{ flex: 1 }} value={form.TesteMiktar}
              onChange={e => onChange({ TesteMiktar: e.target.value })} />
            <select style={{ width: 72 }} value={form.TesteMiktarBirim}
              onChange={e => onChange({ TesteMiktarBirim: e.target.value })}>
              <option value="">—</option>
              {BIRIMLER.map(b => <option key={b} value={b}>{b}</option>)}
            </select>
          </div>
        </div>
        <div className={styles.formGroup}>
          <label>Seri / Lot No</label>
          <input style={inp} value={form.SeriNo}
            onChange={e => onChange({ SeriNo: e.target.value })} />
        </div>
      </div>

      <div className={styles.formGrid3} style={{ marginBottom: 14 }}>
        <div className={styles.formGroup}>
          <label>Üretim Tarihi</label>
          <input type="date" style={inp} value={form.UretimTarihi}
            onChange={e => onChange({ UretimTarihi: e.target.value })} />
        </div>
        <div className={styles.formGroup}>
          <label>SKT</label>
          <input type="date" style={inp} value={form.SKT}
            onChange={e => onChange({ SKT: e.target.value })} />
        </div>
        <div style={{ gridColumn: "3 / span 1" }} />
      </div>

      <div className={styles.formGroup} style={{ marginBottom: 14 }}>
        <label>Notlar</label>
        <textarea rows={3} style={{ width: "100%", resize: "vertical" }}
          value={form.Aciklama}
          onChange={e => onChange({ Aciklama: e.target.value })} />
      </div>

      {/* ── ÜRÜN ÖZELLİKLERİ ── */}
      <Section title="Ürün Özellikleri" />
      <div className={styles.formGrid3} style={{ marginBottom: 14 }}>
        <div className={styles.formGroup}>
          <label>Ürün Tipi</label>
          <select style={inp} value={form.Urun_Tipi}
            onChange={e => onChange({ Urun_Tipi: e.target.value })}>
            <option value="">— Seçin —</option>
            <option value="Durulanan">Durulanan</option>
            <option value="Durulanmayan">Durulanmayan</option>
          </select>
        </div>
        <div className={styles.formGroup}>
          <label>Hedef Grup</label>
          <input style={inp} value={form.Hedef_Grup}
            onChange={e => onChange({ Hedef_Grup: e.target.value })} />
        </div>
        <div />
      </div>

      <div className={styles.formGrid} style={{ marginBottom: 14 }}>
        <div className={styles.formGroup}>
          <label>Kategori</label>
          <select style={inp} value={form.UGDTip_Kategori}
            onChange={e => onChange({ UGDTip_Kategori: e.target.value, UGDTip_ID: null })}>
            <option value="">— Seçin —</option>
            {kategoriler.map(k => <option key={k} value={k}>{k}</option>)}
          </select>
        </div>
        <div className={styles.formGroup}>
          <label>Ürün Türü (UGD)</label>
          <select style={inp} value={form.UGDTip_ID ?? ""}
            disabled={!form.UGDTip_Kategori}
            onChange={e => onChange({ UGDTip_ID: e.target.value ? parseInt(e.target.value) : null })}>
            <option value="">— Seçin —</option>
            {tiplerForKat.map(t => <option key={t.ID} value={t.ID}>{t.UrunTipi}</option>)}
          </select>
        </div>
      </div>

      <div className={styles.formGrid} style={{ marginBottom: 14 }}>
        <div className={styles.formGroup}>
          <label>Uygulama Alanı</label>
          <input readOnly style={{ ...inp, background: "var(--color-surface-2)", color: "var(--color-text-secondary)" }}
            value={selectedTip?.UygulamaBolgesi || ""} />
        </div>
        <div className={styles.formGroup}>
          <label>A Değeri</label>
          <input readOnly style={{ ...inp, background: "var(--color-surface-2)", color: "var(--color-text-secondary)" }}
            value={selectedTip?.ADegeri || ""} />
        </div>
      </div>

      {/* ── FOTOĞRAF ── */}
      <Section title="Ürün Fotoğrafı" />
      <div style={{ display: "flex", gap: 10, alignItems: "flex-start", flexWrap: "wrap" }}>
        <input ref={fileRef} type="file" accept="image/*" style={{ display: "none" }} onChange={handleFotoFile} />
        <button type="button" className={styles.cancelBtn}
          onClick={() => fileRef.current?.click()}>
          Dosyadan Seç
        </button>
        <button type="button" className={styles.cancelBtn}
          onClick={() => setWC(true)}>
          Kameradan Çek
        </button>
        {(form.FotoPreview || form.FotoPath) && (
          <div style={{ display: "flex", alignItems: "center", gap: 10 }}>
            <img
              src={form.FotoPreview || form.FotoPath}
              alt="Ürün fotoğrafı"
              style={{ width: 80, height: 80, objectFit: "cover", borderRadius: 8, border: "1px solid var(--color-border)" }}
            />
            <button type="button" className={styles.cancelBtn} style={{ color: "var(--color-danger)" }}
              onClick={() => onChange({ FotoFile: null, FotoPreview: "", FotoPath: "" })}>
              Kaldır
            </button>
          </div>
        )}
      </div>

      {webcam && <WebcamModal onCapture={handleWebcapture} onClose={() => setWC(false)} />}
    </div>
  );
}

