1	"use client";
2	
3	import { useCallback, useEffect, useState } from "react";
4	import Link from "next/link";
5	import { useRouter } from "next/navigation";
6	import styles from "@/app/styles/table.module.css";
7	import nf from "./numune-form.module.css";
8	import Tab1Bilgiler from "./Tab1Bilgiler";
9	import Tab2Hizmetler from "./Tab2Hizmetler";
10	import Tab3Formul from "./Tab3Formul";
11	import Tab4Gecmis from "./Tab4Gecmis";
12	import type { LookupData, NkrFormData, HizmetRow, FormulRow } from "./numuneFormTypes";
13	import { emptyForm } from "./numuneFormTypes";
14	
15	const TABS = ["Numune bilgileri", "Hizmetler", "Ürün formülü", "Ürün geçmişi"] as const;
16	
17	async function uploadFoto(nkrId: number, file: File) {
18	  const fd = new FormData();
19	  fd.set("file", file);
20	  const res = await fetch(`/api/numune-form/${nkrId}/foto`, { method: "POST", body: fd });
21	  const data = await res.json().catch(() => ({}));
22	  if (!res.ok) throw new Error(data.error || "Foto yüklenemedi");
23	  return data.path as string;
24	}
25	
26	function dat(v: unknown): string {
27	  if (v == null || v === "") return "";
28	  const s = String(v);
29	  return s.includes("T") ? s.split("T")[0]! : s.slice(0, 10);
30	}
31	
32	function d(v: unknown): string {
33	  return v == null ? "" : String(v);
34	}
35	
36	function di(v: unknown): number | null {
37	  if (v == null || v === "") return null;
38	  const n = Number(v);
39	  return Number.isFinite(n) ? n : null;
40	}
41	
42	function mapApiToForm(
43	  nkr: Record<string, unknown>,
44	  detay: Record<string, unknown> | null,
45	  fotoPath: string | null
46	): NkrFormData {
47	  return {
48	    Tarih: dat(nkr.Tarih),
49	    Barkod: d(nkr.Barkod),
50	    Teklif_No: d(nkr.Teklif_No),
51	    Talep_No: d(nkr.Talep_No),
52	    Evrak_No: d(nkr.Evrak_No),
53	    RaporNo: d(nkr.RaporNo),
54	    Revno: d(nkr.Revno) || "0",
55	    Grup: d(nkr.Grup),
56	    Tur: d(nkr.Tur),
57	    Karar: d(nkr.Karar),
58	    Dil: d(nkr.Dil),
59	    Firma_ID: di(nkr.Firma_ID),
60	    FirmaAd: d(nkr.FirmaAd),
61	    ProjeID: detay ? di(detay.ProjeID) : null,
62	    ProjeAd: detay ? d(detay.ProjeAd) : "",
63	    Numune_Adi: d(nkr.Numune_Adi),
64	    Numune_Adi_En: d(nkr.Numune_Adi_En),
65	    Miktar: detay && detay.Miktar != null ? String(detay.Miktar) : "",
66	    Birim: detay ? d(detay.Birim) : "",
67	    TesteMiktar: nkr.TesteMiktar != null ? String(nkr.TesteMiktar) : "",
68	    TesteMiktarBirim: d(nkr.TesteMiktarBirim),
69	    SeriNo: detay ? d(detay.SeriNo) : "",
70	    UretimTarihi: detay ? dat(detay.UretimTarihi) : "",
71	    SKT: detay ? dat(detay.SKT) : "",
72	    Aciklama: d(nkr.Aciklama),
73	    Urun_Tipi: d(nkr.Urun_Tipi),
74	    UGDTip_Kategori: d(nkr.UGDTip_Kategori),
75	    UGDTip_ID: di(nkr.UGDTip_ID),
76	    Hedef_Grup: d(nkr.Hedef_Grup) || "Yetişkinler",
77	    FotoFile: null,
78	    FotoPreview: "",
79	    FotoPath: fotoPath || "",
80	  };
81	}
82	
83	function mapHizmetler(rows: Record<string, unknown>[]): HizmetRow[] {
84	  return rows.map((h, i) => ({
85	    key: `x-${h.ID ?? i}`,
86	    AnalizID: Number(h.AnalizID),
87	    Termin: h.Termin ? dat(h.Termin) : "",
88	    x3ID: h.x3ID != null && h.x3ID !== "" ? Number(h.x3ID) : null,
89	    Kod: d(h.Kod),
90	    Ad: d(h.Ad),
91	    Metot: d(h.Metot),
92	    Sure: h.Sure != null && h.Sure !== "" ? Number(h.Sure) : null,
93	  }));
94	}
95	
96	function mapFormul(rows: Record<string, unknown>[]): FormulRow[] {
97	  return rows.map((f, i) => ({
98	    key: `g-${f.ID ?? i}`,
99	    HammaddeID: di(f.HammaddeID),
100	    INCIName: d(f.INCIName),
101	    Miktar: f.Miktar != null ? String(f.Miktar) : "",
102	    DaP: f.DaP != null ? String(f.DaP) : "",
103	    Noael: f.Noael != null ? String(f.Noael) : "",
104	  }));
105	}
106	
107	export default function NumuneFormClient({ recordId }: { recordId?: string }) {
108	  const router = useRouter();
109	  const [tab, setTab]       = useState(0);
110	  const [lookup, setLookup] = useState<LookupData>({ grupTurleri: [], rUGDTipler: [], paketler: [] });
111	  const [form, setForm]     = useState<NkrFormData>(() => emptyForm());
112	  const [hizmetler, setHizmetler] = useState<HizmetRow[]>([]);
113	  const [formul, setFormul] = useState<FormulRow[]>([]);
114	  const [loadingNos, setLoadingNos] = useState(false);
115	  const [loadErr, setLoadErr]       = useState("");
116	  const [saving, setSaving]         = useState(false);
117	  const [saveErr, setSaveErr]       = useState("");
118	
119	  const isEdit = !!recordId;
120	
121	  useEffect(() => {
122	    fetch("/api/numune-form/lookup")
123	      .then(r => r.json())
124	      .then((data: LookupData) => {
125	        if (data.grupTurleri) setLookup(data);
126	      })
127	      .catch(() => {});
128	  }, []);
129	
130	  useEffect(() => {
131	    if (!recordId) return;
132	    let cancelled = false;
133	    setLoadErr("");
134	    fetch(`/api/numune-form/${recordId}`)
135	      .then(r => r.json())
136	      .then(data => {
137	        if (cancelled) return;
138	        if (!data.nkr) {
139	          setLoadErr(data.error || "Kayıt bulunamadı");
140	          return;
141	        }
142	        setForm(mapApiToForm(data.nkr, data.detay, data.fotoPath ?? null));
143	        setHizmetler(mapHizmetler(data.hizmetler || []));
144	        setFormul(mapFormul(data.formul || []));
145	      })
146	      .catch(() => { if (!cancelled) setLoadErr("Yüklenemedi"); });
147	    return () => { cancelled = true; };
148	  }, [recordId]);
149	
150	  useEffect(() => {
151	    if (isEdit || !form.Grup) return;
152	    let cancelled = false;
153	    (async () => {
154	      setLoadingNos(true);
155	      try {
156	        const r = await fetch(`/api/numune-form/next-no?grup=${encodeURIComponent(form.Grup)}`);
157	        const j = await r.json();
158	        if (cancelled || !r.ok) return;
159	        setForm(f => ({ ...f, Evrak_No: j.evrakNo, RaporNo: j.raporNo }));
160	      } finally {
161	        if (!cancelled) setLoadingNos(false);
162	      }
163	    })();
164	    return () => { cancelled = true; };
165	  }, [form.Grup, isEdit]);
166	
167	  const patchForm = useCallback((u: Partial<NkrFormData>) => {
168	    setForm(f => ({ ...f, ...u }));
169	  }, []);
170	
171	  const buildPayload = () => ({
172	    nkr: {
173	      Tarih: form.Tarih || null,
174	      Barkod: form.Barkod || null,
175	      Teklif_No: form.Teklif_No || null,
176	      Talep_No: form.Talep_No || null,
177	      Evrak_No: form.Evrak_No.trim(),
178	      RaporNo: form.RaporNo.trim(),
179	      Revno: form.Revno,
180	      Grup: form.Grup || null,
181	      Tur: form.Tur || null,
182	      Karar: form.Karar || null,
183	      Dil: form.Dil || null,
184	      Firma_ID: form.Firma_ID,
185	      Aciklama: form.Aciklama || null,
186	      Numune_Adi: form.Numune_Adi.trim(),
187	      Numune_Adi_En: form.Numune_Adi_En || null,
188	      Urun_Tipi: form.Urun_Tipi || null,
189	      UGDTip_ID: form.UGDTip_ID,
190	      Hedef_Grup: form.Hedef_Grup || null,
191	      TesteMiktar: form.TesteMiktar || null,
192	      TesteMiktarBirim: form.TesteMiktarBirim || null,
193	    },
194	    detay: {
195	      ProjeID: form.ProjeID,
196	      Miktar: form.Miktar || null,
197	      Birim: form.Birim || null,
198	      SeriNo: form.SeriNo || null,
199	      UretimTarihi: form.UretimTarihi || null,
200	      SKT: form.SKT || null,
201	    },
202	    hizmetler: hizmetler.map(({ AnalizID, Termin, x3ID }) => ({
203	      AnalizID,
204	      Termin: Termin || null,
205	      x3ID,
206	    })),
207	    formul: formul.map(f => ({
208	      HammaddeID: f.HammaddeID,
209	      INCIName: f.INCIName || null,
210	      Miktar: f.Miktar || null,
211	      DaP: f.DaP || null,
212	      Noael: f.Noael || null,
213	    })),
214	  });
215	
216	  const handleSave = async () => {
217	    setSaveErr("");
218	    if (!form.Evrak_No.trim() || !form.RaporNo.trim() || !form.Numune_Adi.trim()) {
219	      setSaveErr("Evrak No, Rapor No ve Numune Adı zorunludur.");
220	      setTab(0);
221	      return;
222	    }
223	    const body = buildPayload();
224	    setSaving(true);
225	    try {
226	      if (isEdit) {
227	        const res = await fetch(`/api/numune-form/${recordId}`, {
228	          method: "PUT",
229	          headers: { "Content-Type": "application/json" },
230	          body: JSON.stringify(body),
231	        });
232	        const data = await res.json().catch(() => ({}));
233	        if (!res.ok) throw new Error(data.error || "Güncellenemedi");
