      <footer className={nf.saveBar}>
        <button type="button" className={styles.saveBtn} onClick={() => void handleSave()} disabled={saving}>
          {saving ? "Kaydediliyor…" : isEdit ? "Güncelle" : "Kaydet"}
        </button>
