44	}) {
45	  const [q, setQ]           = useState(displayValue);
46	  const [results, setRes]   = useState<{ ID: number; Ad: string }[]>([]);
47	  const [open, setOpen]     = useState(false);
48	  const timer               = useRef<ReturnType<typeof setTimeout> | null>(null);
49	  const wrapRef             = useRef<HTMLDivElement>(null);
50	
51	  useEffect(() => { setQ(displayValue); }, [displayValue]);
52	
53	  useEffect(() => {
54	    const handler = (e: MouseEvent) => {
55	      if (wrapRef.current && !wrapRef.current.contains(e.target as Node)) {
56	        setOpen(false);
57	      }
58	    };
