  font-weight: 650;
  letter-spacing: -0.01em;
  color: var(--color-text-primary);
  margin: 0;
}

.cardHint {
  font-size: 0.72rem;
  color: var(--color-text-tertiary);
  margin: 5px 0 0;
  line-height: 1.4;
  max-width: 52rem;
}

.cardBody {
  padding: 14px 16px 16px;
  display: flex;
  flex-direction: column;
  gap: 12px;
}

/* Kayıt: satır1 Tarih+Grup+Tür+EvrakNo+RaporNo+Rev; satır2 TeklifNo+TalepNo+Karar+Dil */
.gridKayitRow1 {
  display: grid;
  grid-template-columns: minmax(0, 148px) minmax(0, 1fr) minmax(0, 1fr) minmax(0, 1fr) minmax(0, 1fr) minmax(0, 72px);
  gap: 12px 14px;
  align-items: end;
}

.gridKayitRow2 {
  display: grid;
  grid-template-columns: repeat(4, minmax(0, 1fr));
  gap: 12px 14px;
  align-items: end;
}

.gridTwo {
  display: grid;
  grid-template-columns: repeat(2, minmax(0, 1fr));
  gap: 12px 14px;
  align-items: end;
}

/* Barkod + nominal + teste — tek satır */
.gridBarkodRow {
  display: grid;
  grid-template-columns: minmax(0, 140px) minmax(0, 1fr) minmax(0, 1fr);
  gap: 12px 14px;
  align-items: end;
}

.gridSeriRow {
  display: grid;
  grid-template-columns: minmax(0, 1fr) minmax(0, 150px) minmax(0, 150px);
  gap: 12px 14px;
  align-items: end;
}

.notlarArea {
  width: 100%;
  max-width: min(100%, 52rem);
}

.notlarTextarea {
  width: 100%;
  min-width: 0;
