  background: var(--color-surface);
  color: var(--color-text-primary);
  resize: vertical;
  box-sizing: border-box;
}

.numuneAdRow {
  display: flex;
  flex-direction: column;
  gap: 6px;
}

.numuneAdLabelRow {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 10px;
  flex-wrap: wrap;
}

.langToggle {
  display: inline-flex;
  border: 1px solid var(--color-border);
  border-radius: 8px;
  overflow: hidden;
  flex-shrink: 0;
}

.langToggle button {
  padding: 4px 12px;
  font-size: 0.75rem;
  font-weight: 600;
  border: none;
  background: var(--color-surface-2);
  color: var(--color-text-secondary);
  cursor: pointer;
}

.langToggle button[data-on="true"] {
  background: var(--color-accent);
  color: #fff;
}

/* Tarih: içerik kadar yer kaplasın */
.dateWrap {
  max-width: 150px;
  width: 100%;
}

.dateWrap :global(input[type="date"]) {
  width: 100%;
  min-width: 0;
  font-variant-numeric: tabular-nums;
}

.revWrap {
  max-width: 100px;
  width: 100%;
}

.revWrap :global(input) {
  width: 100%;
  text-align: center;
  font-variant-numeric: tabular-nums;
}

/* Miktar satırı: birim sütunu sabit */
.qtyRow {
  display: flex;
  gap: 8px;
  align-items: stretch;
}

.qtyRow :global(input[type="number"]) {
  flex: 1;
  min-width: 0;
}

.qtyRow :global(select) {
  width: 76px;
  flex-shrink: 0;
  font-size: 0.8125rem;
}

.hedefInput :global(input) {
  max-width: min(100%, 260px);
}

.readonlyField :global(input) {
  background: var(--color-surface-2);
  color: var(--color-text-secondary);
  cursor: default;
}

.fotoRow {
  display: flex;
  flex-wrap: wrap;
  align-items: flex-start;
  gap: 10px 12px;
}

.fotoActions {
  display: flex;
  flex-wrap: wrap;
  gap: 8px;
}

.fotoPreview {
  display: flex;
  align-items: center;
  gap: 10px;
  padding: 8px 10px;
  border-radius: var(--radius-sm);
  background: var(--color-surface-2);
  border: 1px solid var(--color-border-light);
}

.fotoPreview img {
  width: 88px;
  height: 88px;
  object-fit: cover;
  border-radius: var(--radius-sm);
  border: 1px solid var(--color-border);
}

@media (max-width: 768px) {
  .gridKayitRowA,
  .gridKayitRowB,
  .gridKayitRowC,
  .gridTwo,
  .gridBarkodRow,
  .gridSeriRow {
    grid-template-columns: 1fr;
  }

  .dateWrap,
  .revWrap {
    max-width: none;
  }
}

