58	// ── Ana bileşen ─────────────────────────────────────────────────
59	export default function NumuneKabulTable() {
60	  const router = useRouter();
61	  const [groups, setGroups]         = useState<EvrakGroup[]>([]);
62	  const [total, setTotal]           = useState(0);
63	  const [page, setPage]             = useState(1);
64	  const [limit, setLimit]           = useState(20);
65	  const [totalPages, setTotalPages] = useState(1);
66	  const [search, setSearch]         = useState("");
67	  const [loading, setLoading]       = useState(true);
68	  const [transitioning, setTransitioning] = useState(false); // sayfa geçişi (skeleton değil, overlay)
69	  const [error, setError]           = useState("");
70	
71	  // Accordion
72	  const [openGroups, setOpenGroups] = useState<Set<string>>(new Set());
73	
74	  const [deleteId, setDeleteId]   = useState<number | null>(null);
75	  const [deleting, setDeleting]   = useState(false);
76	
77	  const searchTimer = useRef<ReturnType<typeof setTimeout> | null>(null);
78	  const abortRef    = useRef<AbortController | null>(null);
79	  const latestReqId = useRef(0); // monotone artan — yalnızca son istek geçerli
80	  const didMount    = useRef(false); // sayfa/limit effect'i mount'ta çalışmasın
81	
82	  // ── Veri çekme ──────────────────────────────────────────────
83	  const fetchData = useCallback(async (
84	    p: number, s: string, l: number,
85	    opts: { clearFirst?: boolean } = {}
86	  ) => {
87	    // Her çağrıya benzersiz ID ver; yalnızca en son ID'li yanıt işlenir
88	    const reqId = ++latestReqId.current;
89	
90	    if (abortRef.current) abortRef.current.abort();
91	    const ctrl = new AbortController();
92	    abortRef.current = ctrl;
93	
94	    if (opts.clearFirst) {
95	      // Arama: eski grupları temizle + skeleton göster
96	      setGroups([]);
97	      setLoading(true);
98	      setTransitioning(false);
99	    } else {
100	      // Sayfa/limit geçişi: eski grupları koru, hafif overlay
101	      setTransitioning(true);
102	      setLoading(false);
103	    }
104	    setError("");
105	
106	    try {
107	      const res = await fetch(
108	        `/api/numune-kabul?page=${p}&limit=${l}&search=${encodeURIComponent(s)}`,
109	        { signal: ctrl.signal }
110	      );
111	
112	      // Eski istek tamamlandıysa yoksay
113	      if (reqId !== latestReqId.current) return;
114	
115	      if (!res.ok) throw new Error((await res.json()).error || "Hata");
116	      const json = await res.json();
117	
118	      setGroups(json.data);
119	      setTotal(json.total);
120	      setTotalPages(json.totalPages);
121	    } catch (e: any) {
122	      if (e.name === "AbortError" || reqId !== latestReqId.current) return;
123	      setError(e.message);
124	    } finally {
125	      if (reqId === latestReqId.current) {
126	        setLoading(false);
127	        setTransitioning(false);
128	      }
129	    }
130	  }, []);
131	
132	  // İlk yükleme — bir kez çalışır
133	  useEffect(() => {
134	    fetchData(1, "", limit, { clearFirst: true });
135	  }, []);
136	
137	  // Sayfa / limit değişimi — mount sonrası her değişimde çalışır
138	  useEffect(() => {
139	    if (!didMount.current) { didMount.current = true; return; }
140	    fetchData(page, search, limit, { clearFirst: false });
141	  }, [page, limit]);
142	
143	  const handleSearch = (val: string) => {
144	    setSearch(val);
145	    if (searchTimer.current) clearTimeout(searchTimer.current);
146	    searchTimer.current = setTimeout(() => {
147	      setPage(1);
148	      fetchData(1, val, limit, { clearFirst: true });
149	    }, 200);
150	  };
151	
152	  // ── Accordion ───────────────────────────────────────────────
153	  const toggleGroup = (evrakNo: string) => {
154	    setOpenGroups(prev => {
155	      const next = new Set(prev);
156	      next.has(evrakNo) ? next.delete(evrakNo) : next.add(evrakNo);
157	      return next;
158	    });
159	  };
160	
161	  const handleDelete = async () => {
162	    if (!deleteId) return;
163	    setDeleting(true);
164	    try {
165	      const res = await fetch(`/api/numune-kabul/${deleteId}`, { method: "DELETE" });
166	      if (!res.ok) throw new Error((await res.json()).error || "Silinemedi");
167	      setDeleteId(null);
168	      fetchData(page, search, limit, { clearFirst: false });
169	    } catch (e: any) { setError(e.message); }
170	    finally { setDeleting(false); }
171	  };
172	
173	  const openNew = () => { router.push("/laboratuvar/numune-form"); };
174	  const openEdit = (n: NumuneItem) => {
175	    window.open(`/laboratuvar/numune-form/${n.ID}`, "_blank", "noopener,noreferrer");
176	  };
177	
178	  // ── Sayfalama ────────────────────────────────────────────────
179	  const goTo = (p: number) => { if (p >= 1 && p <= totalPages) setPage(p); };
180	  const pageNums = () => {
181	    const nums: (number | "…")[] = [];
182	    if (totalPages <= 7) { for (let i = 1; i <= totalPages; i++) nums.push(i); }
183	    else {
184	      nums.push(1);
185	      if (page > 3) nums.push("…");
186	      for (let i = Math.max(2, page - 1); i <= Math.min(totalPages - 1, page + 1); i++) nums.push(i);
187	      if (page < totalPages - 2) nums.push("…");
188	      nums.push(totalPages);
189	    }
190	    return nums;
191	  };
192	
193	  const formatTarih = (t: string | null) => {
