231	            <svg viewBox="0 0 20 20" fill="currentColor" width="15" height="15">
232	              <path d="M10.75 4.75a.75.75 0 0 0-1.5 0v4.5h-4.5a.75.75 0 0 0 0 1.5h4.5v4.5a.75.75 0 0 0 1.5 0v-4.5h4.5a.75.75 0 0 0 0-1.5h-4.5v-4.5Z" />
233	            </svg>
234	            Yeni Numune
235	          </button>
236	        </div>
237	      </div>
238	
239	      {/* ── Accordion listesi ── */}
240	      <div
241	        className={styles.tableCard}
242	        style={{ position: "relative", opacity: transitioning ? 0.55 : 1, transition: "opacity 0.15s" }}
243	      >
244	        {error && <div className={styles.errorBar}>{error}</div>}
245	
246	        {/* ── Kolon başlıkları ── */}
247	        <div style={{
248	          display: "flex", alignItems: "center", gap: 0,
249	          padding: "8px 16px",
250	          borderBottom: "1px solid var(--color-border-light)",
251	          background: "var(--color-surface)",
252	        }}>
253	          <div style={{ width: 24 }} /> {/* chevron */}
254	          <div style={{ width: 88,  fontSize: "0.7rem", fontWeight: 600, textTransform: "uppercase", letterSpacing: "0.06em", color: "var(--color-text-tertiary)" }}>Tarih</div>
255	          <div style={{ width: 130, fontSize: "0.7rem", fontWeight: 600, textTransform: "uppercase", letterSpacing: "0.06em", color: "var(--color-text-tertiary)" }}>Evrak No</div>
256	          <div style={{ flex: 1,    fontSize: "0.7rem", fontWeight: 600, textTransform: "uppercase", letterSpacing: "0.06em", color: "var(--color-text-tertiary)" }}>Firma / Proje</div>
257	          <div style={{ width: 64,  fontSize: "0.7rem", fontWeight: 600, textTransform: "uppercase", letterSpacing: "0.06em", color: "var(--color-text-tertiary)", textAlign: "center" }}>Numune</div>
258	          <div style={{ width: 136,  fontSize: "0.7rem", fontWeight: 600, textTransform: "uppercase", letterSpacing: "0.06em", color: "var(--color-text-tertiary)", textAlign: "center" }}>Ödeme</div>
259	          <div style={{ width: 36,  fontSize: "0.7rem", fontWeight: 600, textTransform: "uppercase", letterSpacing: "0.06em", color: "var(--color-text-tertiary)", textAlign: "center" }}>Fatura</div>
260	        </div>
261	
262	        {/* Skeleton */}
263	        {loading && (
264	          <div style={{ padding: "6px 0" }}>
265	            {Array.from({ length: 6 }).map((_, i) => (
266	              <div key={i} style={{
267	                display: "flex", alignItems: "center", gap: 12,
268	                padding: "14px 20px",
