277	                <span className={styles.skeleton} style={{ width: 28, height: 28, borderRadius: 6 }} />
278	              </div>
279	            ))}
280	          </div>
281	        )}
282	
283	        {/* Boş */}
284	        {!loading && groups.length === 0 && (
285	          <div className={styles.empty}>
286	            <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5" width="36" height="36">
