421	                              borderBottom: ni < group.numuneler.length - 1
422	                                ? "1px solid var(--color-border-light)"
423	                                : "none",
424	                            }}
425	                          >
426	                            <td style={{
427	                              padding: "9px 12px 9px 52px",
428	                              fontWeight: 600, color: "var(--color-accent)",
429	                              fontVariantNumeric: "tabular-nums", whiteSpace: "nowrap",
430	                            }}>
431	                              {n.RaporNo}
432	                            </td>
433	                            <td style={{ padding: "9px 12px", color: "var(--color-text-primary)", fontWeight: 500 }}>
434	                              {n.Numune_Adi}
435	                            </td>
436	                            <td style={{ padding: "9px 12px", color: "var(--color-text-secondary)" }}>
437	                              {[n.Grup, n.Tur].filter(Boolean).join(" / ") || "—"}
438	                            </td>
439	                            <td style={{ padding: "9px 12px", whiteSpace: "nowrap" }}>
440	                              <div className={styles.actionBtns}>
441	                                <button className={styles.editBtn} title="Düzenle" onClick={() => openEdit(n)}>
442	                                  <svg viewBox="0 0 20 20" fill="currentColor" width="13" height="13">
443	                                    <path d="M5.433 13.917l1.262-3.155A4 4 0 0 1 7.58 9.42l6.92-6.918a2.121 2.121 0 0 1 3 3l-6.92 6.918c-.383.383-.84.685-1.343.886l-3.154 1.262a.5.5 0 0 1-.65-.65Z" />
444	                                    <path d="M3.5 5.75c0-.69.56-1.25 1.25-1.25H10A.75.75 0 0 0 10 3H4.75A2.75 2.75 0 0 0 2 5.75v9.5A2.75 2.75 0 0 0 4.75 18h9.5A2.75 2.75 0 0 0 17 15.25V10a.75.75 0 0 0-1.5 0v5.25c0 .69-.56 1.25-1.25 1.25h-9.5c-.69 0-1.25-.56-1.25-1.25v-9.5Z" />
445	                                  </svg>
446	                                </button>
447	                                <button
448	                                  className={styles.editBtn} title="Pasife Al"
449	                                  style={{ color: "#ff3b30" }}
450	                                  onClick={() => setDeleteId(n.ID)}
451	                                >
452	                                  <svg viewBox="0 0 20 20" fill="currentColor" width="13" height="13">
453	                                    <path fillRule="evenodd" d="M8.75 1A2.75 2.75 0 0 0 6 3.75v.443c-.795.077-1.584.176-2.365.298a.75.75 0 1 0 .23 1.482l.149-.022.841 10.518A2.75 2.75 0 0 0 7.596 19h4.807a2.75 2.75 0 0 0 2.742-2.53l.841-10.52.149.023a.75.75 0 0 0 .23-1.482A41.03 41.03 0 0 0 14 4.193V3.75A2.75 2.75 0 0 0 11.25 1h-2.5ZM10 4c.84 0 1.673.025 2.5.075V3.75c0-.69-.56-1.25-1.25-1.25h-2.5c-.69 0-1.25.56-1.25 1.25v.325C8.327 4.025 9.16 4 10 4ZM8.58 7.72a.75.75 0 0 0-1.5.06l.3 7.5a.75.75 0 1 0 1.5-.06l-.3-7.5Zm4.34.06a.75.75 0 1 0-1.5-.06l-.3 7.5a.75.75 0 1 0 1.5.06l.3-7.5Z" clipRule="evenodd" />
454	                                  </svg>
455	                                </button>
456	                              </div>
457	                            </td>
458	                          </tr>
459	                        ))}
460	                      </tbody>
461	                    </table>
462	                  )}
463	                </div>
464	              )}
465	            </div>
466	          );
467	        })}
468	
469	        {/* ── Sayfalama ── */}
470	        {!loading && totalPages > 1 && (
471	          <div className={styles.pagination}>
472	            <button className={styles.pageBtn} onClick={() => goTo(page - 1)} disabled={page === 1 || transitioning}>‹</button>
473	            {pageNums().map((n, i) =>
474	              n === "…"
475	                ? <span key={`d${i}`} className={styles.pageDots}>…</span>
476	                : <button key={n}
477	                    className={`${styles.pageBtn} ${page === n ? styles.pageBtnActive : ""}`}
478	                    disabled={transitioning}
479	                    onClick={() => goTo(n as number)}
480	                  >{n}</button>
481	            )}
482	            <button className={styles.pageBtn} onClick={() => goTo(page + 1)} disabled={page === totalPages || transitioning}>›</button>
483	            <span className={styles.pageInfo}>{total} evrak</span>
484	          </div>
485	        )}
486	      </div>
487	
488	      {/* ── PASİFE AL ONAY ── */}
489	      {deleteId !== null && (
490	        <div className={styles.modalOverlay} onClick={() => setDeleteId(null)}>
491	          <div className={styles.modal} style={{ maxWidth: 380 }} onClick={e => e.stopPropagation()}>
492	            <div className={styles.modalHeader}>
493	              <h2>Pasife Al</h2>
494	              <button className={styles.modalClose} onClick={() => setDeleteId(null)}>
495	                <svg viewBox="0 0 20 20" fill="currentColor" width="14" height="14">
496	                  <path d="M6.28 5.22a.75.75 0 0 0-1.06 1.06L8.94 10l-3.72 3.72a.75.75 0 1 0 1.06 1.06L10 11.06l3.72 3.72a.75.75 0 1 0 1.06-1.06L11.06 10l3.72-3.72a.75.75 0 0 0-1.06-1.06L10 8.94 6.28 5.22Z" />
497	                </svg>
498	              </button>
499	            </div>
500	            <div className={styles.modalBody}>
501	              <p className={styles.deleteWarning}>
502	                Bu numune pasife alınacak ve aktif listeden kaldırılacak. Devam etmek istiyor musunuz?
503	              </p>
504	            </div>
505	            <div className={styles.modalFooter}>
506	              <button className={styles.cancelBtn} onClick={() => setDeleteId(null)} disabled={deleting}>İptal</button>
507	              <button className={styles.deleteBtnPrimary} onClick={handleDelete} disabled={deleting}>
508	                {deleting ? <span className={styles.loader} /> : "Pasife Al"}
509	              </button>
510	            </div>
511	          </div>
512	        </div>
513	      )}
514	    </>
515	  );
