1	"use client";
2	
3	import { useCallback, useRef, useState } from "react";
4	import type { CSSProperties } from "react";
5	import styles from "@/app/styles/table.module.css";
6	import type { HizmetRow } from "./numuneFormTypes";
7	
8	function addDays(isoDate: string, days: number): string {
9	  const base = isoDate ? new Date(isoDate + "T12:00:00") : new Date();
10	  if (Number.isNaN(base.getTime())) return new Date().toISOString().split("T")[0]!;
11	  base.setDate(base.getDate() + Math.max(0, days));
12	  return base.toISOString().split("T")[0]!;
13	}
14	
15	function newKey() {
16	  return `h-${Date.now()}-${Math.random().toString(36).slice(2, 9)}`;
17	}
18	
19	function fmt(n: number | null | undefined) {
20	  if (n == null) return "—";
21	  return n.toLocaleString("tr-TR", { minimumFractionDigits: 2, maximumFractionDigits: 2 });
22	}
23	
24	interface HizmetOpt {
25	  ID: number;
26	  Kod: string;
27	  Ad: string;
28	  Fiyat: number | null;
29	  ParaBirimi: string | null;
30	  Metot?: string;
31	  Sure?: number | null;
32	}
33	
34	interface PaketItem {
35	  HizmetID: number;
36	  HizmetAdi: string;
37	  Kod: string;
38	  Fiyat: number | null;
39	  ParaBirimi: string | null;
40	}
41	
42	interface PaketOpt {
43	  ID: number;
44	  ListeAdi: string;
45	  Aciklama: string;
46	  items: PaketItem[];
47	}
48	
49	interface Props {
50	  tarih: string;
51	  rows: HizmetRow[];
52	  onChange: (rows: HizmetRow[]) => void;
53	}
54	
55	const labelStyle: CSSProperties = {
56	  display: "block",
57	  fontSize: 12,
58	  fontWeight: 600,
59	  textTransform: "uppercase",
60	  letterSpacing: "0.04em",
61	  color: "var(--color-text-secondary)",
62	  marginBottom: 6,
63	};
64	
65	const inputStyle: CSSProperties = {
66	  width: "100%",
67	  padding: "8px 10px",
68	  border: "1px solid var(--color-border)",
69	  borderRadius: 8,
70	  fontSize: 14,
71	  background: "var(--color-surface)",
72	  color: "var(--color-text-primary)",
73	  boxSizing: "border-box",
74	  outline: "none",
75	};
76	
77	const panelStyle: CSSProperties = {
78	  background: "var(--color-bg)",
79	  border: "1px solid var(--color-border)",
80	  borderRadius: 10,
81	  padding: 12,
82	};
83	
84	const thStyle: CSSProperties = {
85	  textAlign: "left",
86	  fontWeight: 600,
87	  fontSize: 12,
88	  color: "var(--color-text-secondary)",
89	  padding: "4px 8px",
90	  whiteSpace: "nowrap",
91	};
92	
93	const tdStyle: CSSProperties = { padding: "6px 8px", verticalAlign: "middle" };
94	
95	const addPanelBtnStyle: CSSProperties = {
96	  padding: "6px 14px",
97	  fontSize: 13,
98	  border: "1px solid var(--color-border)",
99	  borderRadius: 8,
100	  background: "var(--color-surface)",
101	  color: "var(--color-text-primary)",
102	  cursor: "pointer",
103	  fontWeight: 500,
104	};
105	
106	const smallAddBtnStyle: CSSProperties = {
107	  padding: "3px 10px",
108	  fontSize: 12,
109	  border: "1px solid var(--color-accent)",
110	  borderRadius: 6,
111	  background: "transparent",
112	  color: "var(--color-accent)",
113	  cursor: "pointer",
114	  fontWeight: 500,
115	  whiteSpace: "nowrap",
116	};
117	
118	const smallText: CSSProperties = { fontSize: 13, color: "var(--color-text-tertiary)" };
119	
120	function pickAnalizId(row: Record<string, unknown>): number {
121	  const v = row.AnalizID ?? row.analizid;
122	  const n = Number(v);
123	  return Number.isFinite(n) ? n : 0;
124	}
125	
126	function pickStr(row: Record<string, unknown>, ...keys: string[]): string {
127	  for (const k of keys) {
128	    const v = row[k];
129	    if (v != null && v !== "") return String(v);
130	  }
131	  return "";
132	}
133	
134	export default function Tab2Hizmetler({ tarih, rows, onChange }: Props) {
135	  const [addMode, setAddMode] = useState<"hizmet" | "paket" | null>(null);
136	  const [hizmetQ, setHizmetQ] = useState("");
137	  const [hizmetOpts, setHizmetOpts] = useState<HizmetOpt[]>([]);
138	  const [hizmetLoading, setHizmetLoading] = useState(false);
139	  const [paketler, setPaketler] = useState<PaketOpt[]>([]);
140	  const [paketLoading, setPaketLoading] = useState(false);
141	  const [paketExpanded, setPaketExpanded] = useState<number | null>(null);
142	  const [loadingPaketId, setLoadingPaketId] = useState<number | null>(null);
143	  const hizmetTimer = useRef<ReturnType<typeof setTimeout> | null>(null);
144	
145	  const handleHizmetQ = useCallback((val: string) => {
146	    setHizmetQ(val);
147	    if (hizmetTimer.current) clearTimeout(hizmetTimer.current);
148	    hizmetTimer.current = setTimeout(async () => {
149	      setHizmetLoading(true);
150	      try {
151	        const r = await fetch(`/api/teklifler/lookup?type=hizmetler&q=${encodeURIComponent(val)}`);
152	        const j = await r.json();
153	        setHizmetOpts(j.data || []);
154	      } finally {
155	        setHizmetLoading(false);
156	      }
157	    }, 300);
158	  }, []);
159	
160	  async function loadPaketler() {
161	    setPaketLoading(true);
162	    try {
163	      const r = await fetch("/api/teklifler/lookup?type=paketler");
164	      const j = await r.json();
165	      setPaketler(j.data || []);
166	    } finally {
167	      setPaketLoading(false);
168	    }
169	  }
170	
171	  function toggleAddMode(mode: "hizmet" | "paket") {
172	    if (addMode === mode) {
173	      setAddMode(null);
174	      return;
175	    }
176	    setAddMode(mode);
177	    if (mode === "hizmet" && hizmetOpts.length === 0) handleHizmetQ("");
178	    if (mode === "paket" && paketler.length === 0) void loadPaketler();
179	  }
180	
181	  const addHizmet = (h: HizmetOpt) => {
182	    if (rows.some(x => x.AnalizID === h.ID && !x.x3ID)) return;
183	    const metot = h.Metot ?? "";
184	    const termin = addDays(tarih, h.Sure ?? 0);
185	    onChange([
186	      ...rows,
187	      {
188	        key: newKey(),
189	        AnalizID: h.ID,
190	        Termin: termin,
191	        x3ID: null,
192	        Kod: h.Kod,
193	        Ad: h.Ad,
194	        Metot: metot,
195	        Sure: h.Sure ?? null,
196	      },
197	    ]);
198	  };
199	
200	  const addPaketHizmetler = async (x3id: number) => {
201	    setLoadingPaketId(x3id);
202	    try {
203	      const r = await fetch(`/api/numune-form/paket-items?x3id=${x3id}`);
204	      const raw = r.ok ? await r.json() : [];
205	      const items = Array.isArray(raw) ? raw : [];
206	      const next = [...rows];
207	      for (const it of items as Record<string, unknown>[]) {
208	        const aid = pickAnalizId(it);
209	        if (!aid) continue;
210	        if (next.some(x => x.AnalizID === aid && x.x3ID === x3id)) continue;
211	        const sureRaw = it.Sure ?? it.sure;
212	        const sure = sureRaw == null ? null : Number(sureRaw);
213	        next.push({
214	          key: newKey(),
215	          AnalizID: aid,
216	          Termin: addDays(tarih, Number.isFinite(sure as number) ? (sure as number) : 0),
217	          x3ID: x3id,
218	          Kod: pickStr(it, "Kod", "kod"),
219	          Ad: pickStr(it, "Ad", "ad"),
220	          Metot: pickStr(it, "Metot", "metot"),
221	          Sure: Number.isFinite(sure as number) ? (sure as number) : null,
222	        });
223	      }
224	      onChange(next);
225	    } finally {
226	      setLoadingPaketId(null);
227	    }
228	  };
229	
230	  const remove = (key: string) => onChange(rows.filter(r => r.key !== key));
231	
232	  const setTermin = (key: string, termin: string) =>
233	    onChange(rows.map(r => (r.key === key ? { ...r, Termin: termin } : r)));
234	
235	  return (
236	    <div style={{ padding: "20px 24px" }}>
237	      <label style={labelStyle}>Hizmet satırları</label>
238	
239	      <div style={{ display: "flex", gap: 8, marginBottom: 10, flexWrap: "wrap" }}>
240	        {(["hizmet", "paket"] as const).map(mode => (
241	          <button
242	            key={mode}
243	            type="button"
244	            style={{
245	              ...addPanelBtnStyle,
246	              background: addMode === mode ? "var(--color-accent)" : undefined,
247	              color: addMode === mode ? "#fff" : undefined,
248	            }}
249	            onClick={() => toggleAddMode(mode)}
250	          >
251	            {mode === "hizmet" ? "+ Hizmet Ekle" : "≡ Paketten Ekle"}
252	          </button>
253	        ))}
254	      </div>
255	
256	      {addMode === "hizmet" && (
257	        <div style={{ ...panelStyle, marginBottom: 16 }}>
258	          <input
259	            style={{ ...inputStyle, marginBottom: 8 }}
260	            placeholder="Hizmet adı veya kodu ara..."
261	            value={hizmetQ}
262	            onChange={e => handleHizmetQ(e.target.value)}
263	            autoFocus
264	          />
265	          {hizmetLoading ? (
266	            <p style={smallText}>Yükleniyor...</p>
267	          ) : hizmetOpts.length === 0 ? (
268	            <p style={smallText}>Sonuç bulunamadı.</p>
269	          ) : (
270	            <div style={{ maxHeight: 220, overflowY: "auto" }}>
271	              <table style={{ width: "100%", borderCollapse: "collapse", fontSize: 13 }}>
272	                <thead>
273	                  <tr style={{ borderBottom: "1px solid var(--color-border)" }}>
274	                    <th style={thStyle}>Kod</th>
275	                    <th style={thStyle}>Hizmet adı</th>
276	                    <th style={thStyle}>Süre (g)</th>
277	                    <th style={{ ...thStyle, textAlign: "right" }}>Fiyat</th>
278	                    <th style={{ ...thStyle, width: 60 }} />
279	                  </tr>
280	                </thead>
281	                <tbody>
282	                  {hizmetOpts.map(h => (
283	                    <tr key={h.ID} style={{ borderBottom: "1px solid var(--color-border)" }}>
284	                      <td style={{ ...tdStyle, color: "var(--color-text-tertiary)", width: 80 }}>{h.Kod}</td>
285	                      <td style={tdStyle}>{h.Ad}</td>
286	                      <td style={{ ...tdStyle, fontVariantNumeric: "tabular-nums" }}>{h.Sure ?? "—"}</td>
287	                      <td style={{ ...tdStyle, textAlign: "right" }}>
288	                        {h.Fiyat != null ? `${fmt(h.Fiyat)} ${h.ParaBirimi || "TRY"}` : <span style={{ color: "var(--color-text-tertiary)" }}>—</span>}
289	                      </td>
290	                      <td style={tdStyle}>
291	                        <button type="button" style={smallAddBtnStyle} onClick={() => addHizmet(h)}>
292	                          Ekle
293	                        </button>
294	                      </td>
295	                    </tr>
296	                  ))}
297	                </tbody>
298	              </table>
299	            </div>
300	          )}
301	        </div>
302	      )}
303	
304	      {addMode === "paket" && (
305	        <div style={{ ...panelStyle, marginBottom: 16 }}>
306	          {paketLoading ? (
307	            <p style={smallText}>Yükleniyor...</p>
308	          ) : paketler.length === 0 ? (
309	            <p style={smallText}>Aktif paket bulunamadı.</p>
310	          ) : (
311	            <div style={{ maxHeight: 300, overflowY: "auto" }}>
312	              {paketler.map(p => (
313	                <div key={p.ID} style={{ borderBottom: "1px solid var(--color-border)", marginBottom: 4 }}>
314	                  <div
315	                    style={{ display: "flex", alignItems: "center", justifyContent: "space-between", padding: "8px 4px", cursor: "pointer" }}
316	                    onClick={() => setPaketExpanded(prev => (prev === p.ID ? null : p.ID))}
317	                  >
318	                    <div>
319	                      <span style={{ fontWeight: 600, fontSize: 13 }}>{p.ListeAdi}</span>
320	                      <span style={{ color: "var(--color-text-tertiary)", fontSize: 12, marginLeft: 8 }}>{p.items.length} hizmet</span>
321	                      {p.Aciklama ? (
322	                        <span style={{ color: "var(--color-text-secondary)", fontSize: 12, marginLeft: 8 }}>— {p.Aciklama}</span>
323	                      ) : null}
324	                    </div>
325	                    <div style={{ display: "flex", gap: 8, alignItems: "center" }}>
326	                      <button
327	                        type="button"
328	                        style={smallAddBtnStyle}
329	                        disabled={loadingPaketId === p.ID}
330	                        onMouseDown={e => {
331	                          e.stopPropagation();
332	                          void addPaketHizmetler(p.ID);
333	                        }}
334	                      >
335	                        {loadingPaketId === p.ID ? "…" : "Tümünü Ekle"}
336	                      </button>
337	                      <span style={{ color: "var(--color-text-tertiary)", fontSize: 12 }}>{paketExpanded === p.ID ? "▲" : "▼"}</span>
338	                    </div>
339	                  </div>
340	                  {paketExpanded === p.ID && p.items.length > 0 && (
341	                    <div style={{ paddingLeft: 16, paddingBottom: 8 }}>
342	                      {p.items.map((item, idx) => (
343	                        <div
344	                          key={idx}
345	                          style={{
346	                            display: "flex",
347	                            justifyContent: "space-between",
348	                            fontSize: 12,
349	                            padding: "3px 0",
350	                            color: "var(--color-text-secondary)",
351	                          }}
352	                        >
353	                          <span>
354	                            • {item.HizmetAdi}{" "}
355	                            {item.Kod ? <span style={{ color: "var(--color-text-tertiary)" }}>({item.Kod})</span> : null}
356	                          </span>
357	                          <span style={{ marginLeft: 16, flexShrink: 0 }}>
358	                            {item.Fiyat != null ? `${fmt(item.Fiyat)} ${item.ParaBirimi || "TRY"}` : "—"}
359	                          </span>
360	                        </div>
361	                      ))}
362	                    </div>
363	                  )}
364	                </div>
365	              ))}
366	            </div>
367	          )}
368	        </div>
369	      )}
370	
371	      <p style={{ fontSize: "0.78rem", color: "var(--color-text-tertiary)", marginBottom: 20 }}>
372	        Termin, Tab 1&apos;deki tarihe + hizmet süresi (gün) ile hesaplanır; aşağıdan değiştirebilirsiniz.
373	      </p>
374	
375	      {rows.length === 0 ? (
376	        <div className={styles.empty} style={{ padding: 28 }}>
377	          Henüz hizmet eklenmedi.
378	        </div>
379	      ) : (
380	        <div className={styles.tableWrapper}>
381	          <table className={styles.table}>
382	            <thead>
383	              <tr>
384	                <th>Kod</th>
385	                <th>Ad</th>
386	                <th>Metot</th>
387	                <th style={{ width: 160 }}>Termin</th>
388	                <th style={{ width: 56 }} />
389	              </tr>
390	            </thead>
391	            <tbody>
392	              {rows.map(r => (
393	                <tr key={r.key}>
394	                  <td style={{ fontVariantNumeric: "tabular-nums" }}>{r.Kod}</td>
395	                  <td>{r.Ad}</td>
396	                  <td style={{ color: "var(--color-text-secondary)", fontSize: "0.82rem" }}>{r.Metot}</td>
397	                  <td>
398	                    <input
399	                      type="date"
400	                      value={r.Termin?.slice(0, 10) || ""}
401	                      onChange={e => setTermin(r.key, e.target.value)}
