1	import { getServerSession } from "next-auth";
2	import { authOptions } from "@/lib/auth";
3	import poolPromise from "@/lib/db";
4	import { type NextRequest } from "next/server";
5	
6	// ----------------------------------------------------------------
7	// GET  /api/numune-kabul?search=&page=1&limit=20
8	//
9	// Sayfalama: Evrak_No grubu başına 1 sayfa birimi.
10	// Yanıt: { data: EvrakGroup[], total, page, limit, totalPages }
11	// EvrakGroup: { evrakNo, tarih, firmaAd, projeAd, numuneSayisi,
12	//               odemeDurumu, numuneler: NumuneItem[] }
13	// ----------------------------------------------------------------
14	export async function GET(request: NextRequest) {
15	  const session = await getServerSession(authOptions);
16	  if (!session) return Response.json({ error: "Yetkisiz erişim" }, { status: 401 });
17	
18	  const sp     = request.nextUrl.searchParams;
19	  const search = sp.get("search")?.trim() || "";
20	  const page   = Math.max(1, parseInt(sp.get("page")  || "1",  10));
21	  const limit  = Math.min(100, Math.max(5, parseInt(sp.get("limit") || "20", 10)));
22	  const offset = (page - 1) * limit;
23	
24	  try {
25	    const pool = await poolPromise;
26	
27	    // Arama: Evrak_No, RaporNo, FirmaAd, NumuneAdi üzerinde
28	    const searchClause = search
29	      ? `AND (
30	          n.Evrak_No     LIKE N'%' + @search + '%'
31	          OR n.RaporNo   LIKE N'%' + @search + '%'
32	          OR f.Ad        LIKE N'%' + @search + '%'
33	          OR n.Numune_Adi LIKE N'%' + @search + '%'
34	        )`
35	      : "";
36	
37	    const baseJoin = `
38	      FROM NKR n
39	      LEFT JOIN RootTedarikci f ON f.ID = n.Firma_ID
40	      WHERE n.Durum = 'Aktif' ${searchClause}
41	    `;
42	
43	    const signal = request.signal;
44	
45	    // ── Query 1 + 2 paralel: Count ve sayfalanmış gruplar aynı anda ──
46	    const [countResult, groupResult] = await Promise.all([
47	      pool.request()
48	        .input("search", search)
49	        .query(`SELECT COUNT(DISTINCT n.Evrak_No) AS total ${baseJoin}`),
50	
51	      pool.request()
52	        .input("search", search)
53	        .input("offset", offset)
54	        .input("limit",  limit)
55	        .query(`
56	          SELECT
57	            n.Evrak_No,
58	            MIN(CONVERT(varchar(10), n.Tarih, 120))  AS Tarih,
59	            MIN(f.Ad)                                 AS FirmaAd,
60	            COUNT(*)                                  AS NumuneSayisi,
61	            (
62	              SELECT TOP 1 Odeme_Durumu
63	              FROM Odeme
64	              WHERE Evrak_No = n.Evrak_No
65	              ORDER BY ID DESC
66	            )                                         AS Odeme_Durumu,
67	            (
68	              SELECT TOP 1 rt.Ad
69	              FROM   NKR n2
70	              LEFT JOIN NumuneDetay nd ON nd.RaporID = n2.ID
71	              LEFT JOIN RootTedarikci rt ON nd.ProjeID = rt.ID
72	              WHERE  n2.Evrak_No = n.Evrak_No AND n2.Durum = 'Aktif'
73	                AND  rt.Ad IS NOT NULL
74	            )                                         AS ProjeAd
75	          ${baseJoin}
76	          GROUP BY n.Evrak_No
77	          ORDER BY n.Evrak_No DESC
78	          OFFSET @offset ROWS FETCH NEXT @limit ROWS ONLY
79	        `),
80	    ]);
81	
82	    if (signal.aborted) return new Response(null, { status: 499 });
83	
84	    const total  = countResult.recordset[0].total;
85	    const groups = groupResult.recordset as any[];
86	
87	    // ── Query 3: Bu sayfadaki gruplara ait numuneler ──
88	    let numunesByEvrak: Record<string, any[]> = {};
89	    if (groups.length > 0) {
90	      const req3 = pool.request();
91	      const inParams = groups.map((g, i) => {
92	        req3.input(`ev${i}`, g.Evrak_No);
93	        return `@ev${i}`;
94	      }).join(", ");
95	
96	      const numuneResult = await req3.query(`
97	        SELECT
98	          n.ID,
99	          n.Evrak_No,
100	          n.RaporNo,
101	          n.Numune_Adi,
102	          n.Grup,
103	          ng.Tur
104	        FROM NKR n
105	        LEFT JOIN Numune_Grup ng ON n.Grup = ng.Grup
106	        WHERE n.Durum = 'Aktif'
107	          AND n.Evrak_No IN (${inParams})
108	        ORDER BY n.Evrak_No DESC, n.RaporNo DESC
109	      `);
110	
111	      for (const row of numuneResult.recordset) {
112	        if (!numunesByEvrak[row.Evrak_No]) numunesByEvrak[row.Evrak_No] = [];
113	        numunesByEvrak[row.Evrak_No].push(row);
114	      }
115	    }
116	
117	    // ── Merge ──
118	    const data = groups.map(g => ({
119	      evrakNo:      g.Evrak_No,
120	      tarih:        g.Tarih,
121	      firmaAd:      g.FirmaAd,
122	      projeAd:      g.ProjeAd,
123	      numuneSayisi: g.NumuneSayisi,
124	      odemeDurumu:  g.Odeme_Durumu,
125	      numuneler:    numunesByEvrak[g.Evrak_No] ?? [],
126	    }));
127	
128	    return Response.json({ data, total, page, limit, totalPages: Math.ceil(total / limit) });
129	  } catch (e: any) {
130	    return Response.json({ error: e.message }, { status: 500 });
131	  }
132	}
133	
134	// ----------------------------------------------------------------
135	// POST /api/numune-kabul
136	// ----------------------------------------------------------------
137	export async function POST(request: Request) {
138	  const session = await getServerSession(authOptions);
139	  if (!session) return Response.json({ error: "Yetkisiz erişim" }, { status: 401 });
140	
141	  try {
142	    const body = await request.json();
143	    const { Tarih, Evrak_No, RaporNo, Firma_ID, Numune_Adi, Grup } = body;
144	
145	    if (!Evrak_No?.trim())   return Response.json({ error: "Evrak No zorunludur."   }, { status: 400 });
146	    if (!RaporNo?.trim())    return Response.json({ error: "Rapor No zorunludur."   }, { status: 400 });
147	    if (!Numune_Adi?.trim()) return Response.json({ error: "Numune Adı zorunludur." }, { status: 400 });
148	
149	    const pool = await poolPromise;
150	    const result = await pool.request()
151	      .input("Tarih",      Tarih      || null)
152	      .input("Evrak_No",   Evrak_No.trim())
153	      .input("RaporNo",    RaporNo.trim())
154	      .input("Firma_ID",   Firma_ID ? parseInt(Firma_ID) : null)
155	      .input("Numune_Adi", Numune_Adi.trim())
156	      .input("Grup",       Grup       || null)
157	      .query(`
158	        INSERT INTO NKR (Tarih, Evrak_No, RaporNo, Firma_ID, Numune_Adi, Grup, Durum)
159	        OUTPUT INSERTED.ID
160	        VALUES (@Tarih, @Evrak_No, @RaporNo, @Firma_ID, @Numune_Adi, @Grup, 'Aktif')
161	      `);
162	
163	    return Response.json({ id: result.recordset[0].ID }, { status: 201 });
164	  } catch (e: any) {
165	    return Response.json({ error: e.message }, { status: 500 });
166	  }
167	}
