function newCardId() { return `c-${Date.now()}-${Math.random().toString(36).slice(2, 7)}`; }
function newHizmetKey() { return `h-${Date.now()}-${Math.random().toString(36).slice(2, 7)}`; }

function emptyCard(partial: Partial<NumuneCard> = {}): NumuneCard {
