              value={form.Hedef_Grup}
              onChange={e => onChange({ Hedef_Grup: e.target.value })}
              list="hedef-grup-oneri"
              placeholder="Önerilerden seçin veya yazın…"
            />
          </div>
        </div>

        <div className={styles.formGroup}>
          <label>Kategori — UGD ürün türü</label>
          <select
            style={sel}
            value={form.UGDTip_ID != null ? String(form.UGDTip_ID) : ""}
            onChange={e => {
              const v = e.target.value;
              if (!v) {
                onChange({ UGDTip_ID: null, UGDTip_Kategori: "" });
                return;
              }
              const id = parseInt(v, 10);
              const tip = lookup.rUGDTipler.find(t => t.ID === id);
              onChange({
                UGDTip_ID: id,
                UGDTip_Kategori: tip?.Kategori ?? "",
              });
            }}
          >
            <option value="">Seçin</option>
            {ugdTipSorted.map(t => (
              <option key={t.ID} value={t.ID}>
                {t.Kategori} — {t.UrunTipi}
              </option>
            ))}
          </select>
        </div>

        <div className={t1.gridTwo}>
          <div className={`${styles.formGroup} ${t1.readonlyField}`}>
            <label>Uygulama alanı</label>
            <input readOnly value={selectedTip?.UygulamaBolgesi || ""} placeholder="—" />
          </div>
          <div className={`${styles.formGroup} ${t1.readonlyField}`}>
            <label>A değeri</label>
            <input readOnly value={selectedTip?.ADegeri || ""} placeholder="—" />
          </div>
        </div>
      </Card>

      <Card title="Ürün fotoğrafı" hint="Dosya yükleyin veya kameradan çekin. Kayıt sırasında sunucuya aktarılır.">
        <div className={t1.fotoRow}>
          <input ref={fileRef} type="file" accept="image/*" style={{ display: "none" }} onChange={handleFotoFile} />
          <div className={t1.fotoActions}>
            <button type="button" className={styles.cancelBtn} onClick={() => fileRef.current?.click()}>
              Dosyadan seç
            </button>
            <button type="button" className={styles.cancelBtn} onClick={() => setWC(true)}>
              Kameradan çek
            </button>
          </div>
          {(form.FotoPreview || form.FotoPath) ? (
            <div className={t1.fotoPreview}>
              <img src={form.FotoPreview || form.FotoPath} alt="Ürün önizleme" />
              <button type="button" className={styles.cancelBtn} style={{ color: "var(--color-danger)" }}
                onClick={() => onChange({ FotoFile: null, FotoPreview: "", FotoPath: "" })}>
                Kaldır
              </button>
            </div>
          ) : null}
        </div>
      </Card>

      {webcam ? <WebcamModal onCapture={handleWebcapture} onClose={() => setWC(false)} /> : null}
    </div>
  );
}

