const AYLAR = ["Oca","Şub","Mar","Nis","May","Haz","Tem","Ağu","Eyl","Eki","Kas","Ara"];

function PartialDateInput({ value, onChange }: { value: string; onChange: (v: string) => void }) {
  const parts = value ? value.split("-") : [];
  const yil = parts[0] ?? "";
  const ay  = parts[1] ?? "";
  const gun = parts[2] ?? "";

  const update = (newY: string, newM: string, newD: string) => {
    if (!newY) { onChange(""); return; }
    if (!newM)  { onChange(newY); return; }
    if (!newD)  { onChange(`${newY}-${newM.padStart(2,"0")}`); return; }
    onChange(`${newY}-${newM.padStart(2,"0")}-${newD.padStart(2,"0")}`);
  };

  const ss: React.CSSProperties = { padding: "7px 4px", border: "1px solid var(--color-border)", borderRadius: "var(--radius-sm)", background: "var(--color-surface)", color: "var(--color-text-primary)", fontSize: "0.8125rem", cursor: "pointer", boxSizing: "border-box" };

  return (
    <div style={{ display: "flex", gap: 4 }}>
      <input type="number" min={1990} max={2100} placeholder="Yıl" value={yil}
