        style={{ ...ss, width: 68, textAlign: "center" }} />
      <select value={ay} onChange={e => update(yil, e.target.value, gun)} style={{ ...ss, flex: 1 }}>
        <option value="">Ay</option>
        {AYLAR.map((a, i) => <option key={i} value={String(i+1).padStart(2,"0")}>{a}</option>)}
      </select>
      <select value={gun} onChange={e => update(yil, ay, e.target.value)} disabled={!ay} style={{ ...ss, width: 52 }}>
