      setLoading(true);
      try {
        const r = await fetch(`/api/teklifler/lookup?type=hizmetler&q=${encodeURIComponent(val)}`);
        const j = await r.json();
        setOpts(j.data || []);
        setOpen(true);
      } finally { setLoading(false); }
    }, 300);
  };

  const addHizmet = (h: any) => {
    if (rows.some(x => x.AnalizID === h.ID)) return;
    const base = tarih ? new Date(tarih + "T12:00:00") : new Date();
    base.setDate(base.getDate() + (h.Sure ?? 0));
    const termin = base.toISOString().split("T")[0]!;
    onChange([...rows, { key: newHizmetKey(), AnalizID: h.ID, Termin: termin, x3ID: null, Kod: h.Kod, Ad: h.Ad, Metot: h.Metot ?? "", Sure: h.Sure ?? null }]);
    setQ(""); setOpts([]); setOpen(false);
  };

  const remove = (key: string) => onChange(rows.filter(r => r.key !== key));

  return (
    <div className={yn.hizmetSection}>
      <div className={yn.hizmetSectionTitle}>Hizmetler</div>
      <div style={{ position: "relative", marginBottom: 8 }}>
        <input
          value={q}
          onChange={e => search(e.target.value)}
          placeholder="Hizmet adı veya kodu…"
          style={{ width: "100%", padding: "6px 10px", border: "1px solid var(--color-border)", borderRadius: "var(--radius-sm)", fontSize: "0.8125rem", background: "var(--color-surface)", color: "var(--color-text-primary)", boxSizing: "border-box" }}
        />
        {open && opts.length > 0 && (
          <div style={{ position: "absolute", top: "100%", left: 0, right: 0, zIndex: 200, background: "var(--color-surface)", border: "1px solid var(--color-border)", borderRadius: "var(--radius-sm)", boxShadow: "0 4px 12px rgba(0,0,0,0.1)", maxHeight: 180, overflowY: "auto" }}>
            {loading ? <div style={{ padding: "8px 12px", fontSize: "0.8rem", color: "var(--color-text-tertiary)" }}>Yükleniyor…</div> : opts.map(h => (
              <div key={h.ID}
                style={{ display: "flex", justifyContent: "space-between", alignItems: "center", padding: "7px 12px", cursor: "pointer", fontSize: "0.8125rem", borderBottom: "1px solid var(--color-border-light)" }}
                onMouseDown={() => addHizmet(h)}
                onMouseEnter={e => (e.currentTarget.style.background = "var(--color-surface-2)")}
                onMouseLeave={e => (e.currentTarget.style.background = "transparent")}
              >
                <span><strong style={{ color: "var(--color-text-tertiary)", marginRight: 6 }}>{h.Kod}</strong>{h.Ad}</span>
                <span style={{ fontSize: "0.75rem", color: "var(--color-text-tertiary)", marginLeft: 8, flexShrink: 0 }}>{h.Sure ? `${h.Sure} g` : ""}</span>
              </div>
            ))}
          </div>
        )}
      </div>
      {rows.length > 0 && (
        <table style={{ width: "100%", borderCollapse: "collapse", fontSize: "0.8rem" }}>
          <thead>
            <tr style={{ borderBottom: "1px solid var(--color-border-light)" }}>
              <th style={{ textAlign: "left", padding: "4px 8px", fontWeight: 600, color: "var(--color-text-secondary)", fontSize: "0.72rem", textTransform: "uppercase" }}>Kod</th>
              <th style={{ textAlign: "left", padding: "4px 8px", fontWeight: 600, color: "var(--color-text-secondary)", fontSize: "0.72rem", textTransform: "uppercase" }}>Hizmet</th>
              <th style={{ textAlign: "left", padding: "4px 8px", fontWeight: 600, color: "var(--color-text-secondary)", fontSize: "0.72rem", textTransform: "uppercase", width: 140 }}>Termin</th>
              <th style={{ width: 32 }} />
            </tr>
          </thead>
          <tbody>
            {rows.map(r => (
              <tr key={r.key} style={{ borderBottom: "1px solid var(--color-border-light)" }}>
                <td style={{ padding: "5px 8px", color: "var(--color-text-tertiary)", fontVariantNumeric: "tabular-nums" }}>{r.Kod}</td>
                <td style={{ padding: "5px 8px" }}>{r.Ad}</td>
                <td style={{ padding: "5px 8px" }}>
                  <input type="date" value={r.Termin?.slice(0,10) || ""} onChange={e => onChange(rows.map(x => x.key === r.key ? {...x, Termin: e.target.value} : x))} style={{ width: "100%", padding: "3px 6px", border: "1px solid var(--color-border)", borderRadius: 4, fontSize: "0.8rem", background: "var(--color-surface)" }} />
                </td>
                <td style={{ padding: "5px 4px" }}>
                  <button type="button" onClick={() => remove(r.key)} style={{ background: "none", border: "none", cursor: "pointer", color: "var(--color-text-tertiary)", fontSize: "0.85rem", padding: 2 }}>✕</button>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      )}
    </div>
  );
}

// ── Ana bileşen ────────────────────────────────────────────
export default function YeniNumuneClient() {
  const today = new Date().toISOString().split("T")[0]!;

  const [evrak, setEvrak] = useState<EvrakForm>({
    Tarih: today, Evrak_No: "", Teklif_No: "", Talep_No: "",
    Karar: "Basit Karar Kuralı", Dil: "Türkçe",
    Firma_ID: null, FirmaAd: "", ProjeID: null, ProjeAd: "", Grup: "Özel",
  });
  const [evrakOpen, setEvrakOpen] = useState(true);
  const [evrakSaved, setEvrakSaved] = useState(false);
  const [loadingNos, setLoadingNos] = useState(false);

  const [numuneler, setNumuneler] = useState<NumuneCard[]>([]);
  const [lookup, setLookup] = useState<LookupData>({ grupTurleri: [], rUGDTipler: [], paketler: [] });

  // Load lookup data
  useEffect(() => {
    fetch("/api/numune-form/lookup").then(r => r.json()).then((d: LookupData) => { if (d.grupTurleri) setLookup(d); }).catch(() => {});
  }, []);

  // Auto-fill Evrak_No when Grup changes (if not yet filled)
  useEffect(() => {
    if (!evrak.Grup || evrak.Evrak_No) return;
    let cancelled = false;
    (async () => {
      setLoadingNos(true);
      try {
        const r = await fetch(`/api/numune-form/next-no?grup=${encodeURIComponent(evrak.Grup)}`);
        const j = await r.json();
        if (!cancelled && r.ok) setEvrak(e => ({ ...e, Evrak_No: j.evrakNo }));
      } finally { if (!cancelled) setLoadingNos(false); }
    })();
    return () => { cancelled = true; };
  }, [evrak.Grup]);

  const patchEvrak = (u: Partial<EvrakForm>) => setEvrak(e => ({ ...e, ...u }));

  // Fetch next Rapor No for a new card
  const fetchNextRaporNo = async (): Promise<string> => {
    try {
      const r = await fetch(`/api/numune-form/next-no?grup=${encodeURIComponent(evrak.Grup || "Özel")}`);
      const j = await r.json();
      return r.ok ? j.raporNo : "";
    } catch { return ""; }
  };

  const addNumune = async () => {
    const raporNo = await fetchNextRaporNo();
    const card = emptyCard({ RaporNo: raporNo, Tur: "" });
    setNumuneler(prev => [...prev, card]);
  };

  const patchCard = (cardId: string, update: Partial<NumuneCard>) => {
    setNumuneler(prev => prev.map(c => c.cardId === cardId ? { ...c, ...update } : c));
  };

  const removeCard = (cardId: string) => {
    setNumuneler(prev => prev.filter(c => c.cardId !== cardId));
  };

  const saveCard = async (card: NumuneCard) => {
    if (!card.Numune_Adi.trim()) { patchCard(card.cardId, { error: "Numune Adı zorunludur." }); return; }
    if (!card.RaporNo.trim()) { patchCard(card.cardId, { error: "Rapor No zorunludur." }); return; }
    if (!evrak.Evrak_No.trim()) { patchCard(card.cardId, { error: "Önce Evrak No girin." }); return; }

    patchCard(card.cardId, { saving: true, error: "" });

    const body = {
      nkr: {
        Tarih: evrak.Tarih || null,
        Barkod: card.Barkod || null,
        Teklif_No: evrak.Teklif_No || null,
        Talep_No: evrak.Talep_No || null,
        Evrak_No: evrak.Evrak_No.trim(),
        RaporNo: card.RaporNo.trim(),
        Revno: "0",
        Grup: evrak.Grup || null,
        Tur: card.Tur || null,
        Karar: evrak.Karar || null,
        Dil: evrak.Dil || null,
        Firma_ID: evrak.Firma_ID,
        Numune_Adi: card.Numune_Adi.trim(),
        Numune_Adi_En: card.Numune_Adi_En || null,
        Urun_Tipi: card.Urun_Tipi || null,
        UGDTip_ID: card.UGDTip_ID,
        Hedef_Grup: card.Hedef_Grup || null,
        TesteMiktar: card.TesteMiktar || null,
        TesteMiktarBirim: card.TesteMiktarBirim || null,
        Aciklama: card.Aciklama || null,
      },
      detay: {
        ProjeID: evrak.ProjeID,
        Miktar: card.Miktar || null,
        Birim: card.Birim || null,
        SeriNo: card.SeriNo || null,
        UretimTarihi: normalizePartialDate(card.UretimTarihi),
        SKT: normalizePartialDate(card.SKT),
      },
      hizmetler: card.hizmetler.map(h => ({ AnalizID: h.AnalizID, Termin: h.Termin || null, x3ID: h.x3ID })),
      formul: [],
    };

    const url = card.savedId ? `/api/numune-form/${card.savedId}` : "/api/numune-form";
    const method = card.savedId ? "PUT" : "POST";

    try {
      const res = await fetch(url, { method, headers: { "Content-Type": "application/json" }, body: JSON.stringify(body) });
      const data = await res.json().catch(() => ({}));
      if (!res.ok) throw new Error(data.error || "Kaydedilemedi");
      const newSavedId = card.savedId ?? (data.id as number);
      patchCard(card.cardId, { saving: false, saved: true, savedId: newSavedId, open: false });
      setEvrakSaved(true);
    } catch (e: any) {
      patchCard(card.cardId, { saving: false, error: e.message || "Hata" });
    }
  };

  const turler = evrak.Grup
    ? lookup.grupTurleri.filter(g => g.Grup === evrak.Grup).map(g => g.Tur)
    : [];

  const sel: React.CSSProperties = { width: "100%" };

  return (
    <div className={yn.page}>
      {/* Toolbar */}
      <div className={yn.toolbar}>
        <div>
          <div className={yn.title}>Yeni Numune Girişi <span style={{ fontSize: "0.7rem", verticalAlign: "middle", padding: "2px 8px", background: "#0071e320", color: "#0071e3", borderRadius: 8, marginLeft: 6 }}>Önizleme</span></div>
          <div className={yn.subtitle}>Tek evrak için birden fazla numune ekleyebilirsiniz.</div>
        </div>
        <Link href="/laboratuvar/numune-takip" className={yn.backLink}>← Listeye dön</Link>
      </div>

      {/* ── Evrak Bilgileri ── */}
      <div className={yn.evrakCard}>
        <div
          className={`${yn.evrakCardHead} ${evrakOpen ? yn.open : ""}`}
          onClick={() => setEvrakOpen(o => !o)}
        >
          <div className={yn.evrakCardTitle}>
            <svg viewBox="0 0 20 20" fill="currentColor" width="14" height="14" style={{ color: "var(--color-text-tertiary)", transform: evrakOpen ? "rotate(90deg)" : "rotate(0deg)", transition: "transform 0.15s" }}>
              <path fillRule="evenodd" d="M7.21 14.77a.75.75 0 0 1 .02-1.06L11.168 10 7.23 6.29a.75.75 0 1 1 1.04-1.08l4.5 4.25a.75.75 0 0 1 0 1.08l-4.5 4.25a.75.75 0 0 1-1.06-.02Z" clipRule="evenodd" />
            </svg>
            Evrak Bilgileri
          </div>
          {!evrakOpen && evrakSaved && (
            <div className={yn.evrakSummary}>
              {evrak.FirmaAd && <span className={yn.evrakSummaryItem}><span className={yn.evrakSummaryLabel}>Firma:</span> <strong>{evrak.FirmaAd}</strong></span>}
              {evrak.Evrak_No && <span className={yn.evrakSummaryItem}><span className={yn.evrakSummaryLabel}>Evrak:</span> <strong>{evrak.Evrak_No}</strong></span>}
              {evrak.Grup && <span className={yn.evrakSummaryItem}><span className={yn.evrakSummaryLabel}>Grup:</span> <strong>{evrak.Grup}</strong></span>}
            </div>
          )}
        </div>

        {evrakOpen && (
          <div className={yn.evrakBody}>
            <div className={yn.evrakGrid}>
              <div className={yn.fg}>
                <label>Tarih</label>
                <input type="date" style={sel} value={evrak.Tarih} onChange={e => patchEvrak({ Tarih: e.target.value })} />
              </div>
              <div className={yn.fg}>
                <label>Ürün grubu</label>
                <select style={sel} value={evrak.Grup} onChange={e => patchEvrak({ Grup: e.target.value })}>
                  {GRUPLAR.map(g => <option key={g} value={g}>{g}</option>)}
                </select>
              </div>
              <div className={yn.fg}>
                <label>Evrak No {loadingNos && <span style={{ fontWeight: 400, color: "var(--color-text-tertiary)", fontSize: "0.7rem" }}>…</span>}</label>
                <input style={sel} value={evrak.Evrak_No} onChange={e => patchEvrak({ Evrak_No: e.target.value })} />
              </div>
              <div className={yn.fg}>
                <label>Teklif No</label>
                <input style={sel} value={evrak.Teklif_No} onChange={e => patchEvrak({ Teklif_No: e.target.value })} />
              </div>
              <div className={yn.fg}>
                <label>Talep No</label>
                <input style={sel} value={evrak.Talep_No} onChange={e => patchEvrak({ Talep_No: e.target.value })} />
              </div>
            </div>
            <div className={yn.evrakGrid2}>
              <FirmaSearch label="Firma" value={evrak.Firma_ID} displayValue={evrak.FirmaAd} onChange={(id, ad) => patchEvrak({ Firma_ID: id, FirmaAd: ad })} placeholder="Firma adı…" />
              <FirmaSearch label="Proje" value={evrak.ProjeID} displayValue={evrak.ProjeAd} onChange={(id, ad) => patchEvrak({ ProjeID: id, ProjeAd: ad })} placeholder="Proje adı…" />
              <div className={yn.fg}>
                <label>Karar kuralı</label>
                <select style={sel} value={evrak.Karar} onChange={e => patchEvrak({ Karar: e.target.value })}>
                  {KARALAR.map(k => <option key={k} value={k}>{k}</option>)}
                </select>
              </div>
              <div className={yn.fg}>
                <label>Raporlama dili</label>
                <select style={sel} value={evrak.Dil} onChange={e => patchEvrak({ Dil: e.target.value })}>
                  {DILLER.map(d => <option key={d} value={d}>{d}</option>)}
                </select>
              </div>
            </div>
            <div style={{ display: "flex", justifyContent: "flex-end" }}>
              <button
                type="button"
                style={{ padding: "6px 16px", background: "var(--color-surface-2)", border: "1px solid var(--color-border)", borderRadius: "var(--radius-sm)", fontSize: "0.8125rem", cursor: "pointer", fontWeight: 500 }}
                onClick={() => { setEvrakOpen(false); setEvrakSaved(true); }}
              >
                Tamam, numune ekle →
              </button>
            </div>
          </div>
        )}
      </div>

      {/* ── Numune listesi ── */}
      <div className={yn.numuneListHeader}>
        <div className={yn.numuneListTitle}>
          Numuneler
          {numuneler.length > 0 && (
            <span style={{ marginLeft: 8, padding: "2px 9px", background: "var(--color-accent-light)", color: "var(--color-accent)", borderRadius: 10, fontSize: "0.72rem", fontWeight: 600 }}>
              {numuneler.length}
            </span>
          )}
        </div>
        <button type="button" className={yn.addBtn} onClick={() => void addNumune()}>
          <svg viewBox="0 0 20 20" fill="currentColor" width="14" height="14">
            <path d="M10.75 4.75a.75.75 0 0 0-1.5 0v4.5h-4.5a.75.75 0 0 0 0 1.5h4.5v4.5a.75.75 0 0 0 1.5 0v-4.5h4.5a.75.75 0 0 0 0-1.5h-4.5v-4.5Z" />
          </svg>
          Numune Ekle
        </button>
      </div>

      {numuneler.length === 0 && (
        <div style={{ textAlign: "center", padding: "40px 20px", background: "var(--color-surface)", border: "2px dashed var(--color-border-light)", borderRadius: "var(--radius-md)", color: "var(--color-text-tertiary)", fontSize: "0.845rem" }}>
          Henüz numune eklenmedi. Yukarıdaki "+ Numune Ekle" butonunu kullanın.
        </div>
      )}

      {numuneler.map((card) => {
        const cardTurler = evrak.Grup ? lookup.grupTurleri.filter(g => g.Grup === evrak.Grup).map(g => g.Tur) : [];
        return (
          <div key={card.cardId} className={yn.numuneCard}>
            {/* Kart başlığı */}
            <div
              className={`${yn.numuneCardHead} ${card.open ? yn.open : ""}`}
              onClick={() => patchCard(card.cardId, { open: !card.open })}
            >
              <svg viewBox="0 0 20 20" fill="currentColor" width="12" height="12" style={{ color: "var(--color-text-tertiary)", flexShrink: 0, transform: card.open ? "rotate(90deg)" : "rotate(0deg)", transition: "transform 0.15s" }}>
                <path fillRule="evenodd" d="M7.21 14.77a.75.75 0 0 1 .02-1.06L11.168 10 7.23 6.29a.75.75 0 1 1 1.04-1.08l4.5 4.25a.75.75 0 0 1 0 1.08l-4.5 4.25a.75.75 0 0 1-1.06-.02Z" clipRule="evenodd" />
              </svg>
              {card.RaporNo
                ? <span className={yn.numuneRaporNo}>{card.RaporNo}</span>
                : <span className={yn.numuneRaporNoEmpty}>Rapor No…</span>
              }
              <span className={yn.numuneAd}>{card.Numune_Adi || <span style={{ color: "var(--color-text-tertiary)", fontStyle: "italic" }}>Numune adı girilmedi</span>}</span>
              {[evrak.Grup, card.Tur].filter(Boolean).length > 0 && (
                <span className={yn.numuneGrupTur}>{[evrak.Grup, card.Tur].filter(Boolean).join(" / ")}</span>
              )}
              {card.hizmetler.length > 0 && (
                <span className={yn.numuneBadge}>{card.hizmetler.length} hizmet</span>
              )}
              {card.saved && !card.open && (
                <span className={yn.savedBadge}>✓ Kaydedildi</span>
              )}
            </div>

            {/* Kart gövdesi */}
            {card.open && (
              <div className={yn.numuneCardBody}>
                {card.error && <div className={yn.cardErr}>{card.error}</div>}

                {/* İlk satır: Rapor No + Numune Adı TR + Numune Adı EN + Tür */}
                <div className={yn.numuneInfoGrid}>
                  <div className={yn.fg}>
                    <label>Numune Adı (TR) *</label>
                    <input style={sel} value={card.Numune_Adi} onChange={e => patchCard(card.cardId, { Numune_Adi: e.target.value })} placeholder="Türkçe ad…" />
                  </div>
                  <div className={yn.fg}>
                    <label>Numune Adı (EN)</label>
                    <input style={sel} value={card.Numune_Adi_En} onChange={e => patchCard(card.cardId, { Numune_Adi_En: e.target.value })} placeholder="English name…" />
                  </div>
                  <div className={yn.fg}>
                    <label>Rapor No *</label>
                    <input style={sel} value={card.RaporNo} onChange={e => patchCard(card.cardId, { RaporNo: e.target.value })} />
                  </div>
                  <div className={yn.fg}>
                    <label>Ürün türü</label>
                    <select style={sel} value={card.Tur} onChange={e => patchCard(card.cardId, { Tur: e.target.value })} disabled={cardTurler.length === 0}>
                      <option value="">Seçin</option>
                      {cardTurler.map(t => <option key={t} value={t}>{t}</option>)}
                    </select>
                  </div>
                </div>

                {/* İkinci satır: Barkod + Nominal + Teste + Seri + ÜretimTarihi + SKT */}
                <div className={yn.numuneInfoGrid2}>
                  <div className={yn.fg}>
                    <label>Barkod</label>
                    <input style={sel} value={card.Barkod} onChange={e => patchCard(card.cardId, { Barkod: e.target.value })} />
                  </div>
                  <div className={yn.fg}>
                    <label>Nominal miktar</label>
                    <div style={{ display: "flex", gap: 4 }}>
                      <input type="number" min={0} placeholder="0" value={card.Miktar} onChange={e => patchCard(card.cardId, { Miktar: e.target.value })} style={{ flex: 1, padding: "7px 8px", border: "1px solid var(--color-border)", borderRadius: "var(--radius-sm)", fontSize: "0.8375rem", background: "var(--color-surface)", minWidth: 0 }} />
                      <select value={card.Birim} onChange={e => patchCard(card.cardId, { Birim: e.target.value })} style={{ width: 62, padding: "7px 4px", border: "1px solid var(--color-border)", borderRadius: "var(--radius-sm)", fontSize: "0.8125rem", background: "var(--color-surface)" }}>
                        <option value="">—</option>
                        {BIRIMLER.map(b => <option key={b} value={b}>{b}</option>)}
                      </select>
                    </div>
                  </div>
                  <div className={yn.fg}>
                    <label>Teste gelen miktar</label>
                    <div style={{ display: "flex", gap: 4 }}>
                      <input type="number" min={0} placeholder="0" value={card.TesteMiktar} onChange={e => patchCard(card.cardId, { TesteMiktar: e.target.value })} style={{ flex: 1, padding: "7px 8px", border: "1px solid var(--color-border)", borderRadius: "var(--radius-sm)", fontSize: "0.8375rem", background: "var(--color-surface)", minWidth: 0 }} />
                      <select value={card.TesteMiktarBirim} onChange={e => patchCard(card.cardId, { TesteMiktarBirim: e.target.value })} style={{ width: 62, padding: "7px 4px", border: "1px solid var(--color-border)", borderRadius: "var(--radius-sm)", fontSize: "0.8125rem", background: "var(--color-surface)" }}>
                        <option value="">—</option>
                        {BIRIMLER.map(b => <option key={b} value={b}>{b}</option>)}
                      </select>
                    </div>
                  </div>
                  <div className={yn.fg}>
                    <label>Seri / Lot</label>
                    <input style={sel} value={card.SeriNo} onChange={e => patchCard(card.cardId, { SeriNo: e.target.value })} />
                  </div>
                  <div className={yn.fg}>
                    <label>Üretim tarihi</label>
                    <PartialDateInput value={card.UretimTarihi} onChange={v => patchCard(card.cardId, { UretimTarihi: v })} />
                  </div>
                  <div className={yn.fg}>
                    <label>SKT</label>
                    <PartialDateInput value={card.SKT} onChange={v => patchCard(card.cardId, { SKT: v })} />
                  </div>
                </div>

                {/* Hizmetler */}
                <HizmetPanel
                  tarih={evrak.Tarih}
                  rows={card.hizmetler}
                  onChange={rows => patchCard(card.cardId, { hizmetler: rows })}
                />

                {/* Footer */}
                <div className={yn.numuneCardFooter}>
                  <button type="button" className={yn.deleteCardBtn} onClick={() => removeCard(card.cardId)} disabled={card.saving}>
                    Kartı Kaldır
                  </button>
                  <button type="button" className={yn.saveCardBtn} onClick={() => void saveCard(card)} disabled={card.saving}>
                    {card.saving ? "Kaydediliyor…" : card.savedId ? "Güncelle" : "Kaydet"}
                  </button>
                </div>
              </div>
            )}
          </div>
        );
      })}
    </div>
  );
}

"use client";

import { useState, useCallback, useRef, useEffect } from "react";
import Link from "next/link";
import yn from "./yeni-numune.module.css";
import type { HizmetRow, LookupData } from "../numune-form/numuneFormTypes";

// ── Tipler ────────────────────────────────────────────────
interface EvrakForm {
  Tarih: string;
  Evrak_No: string;
  Teklif_No: string;
  Talep_No: string;
  Karar: string;
  Dil: string;
  Firma_ID: number | null;
  FirmaAd: string;
  ProjeID: number | null;
  ProjeAd: string;
  Grup: string;
}

interface NumuneCard {
  cardId: string;
  savedId: number | null;
  RaporNo: string;
  Numune_Adi: string;
  Numune_Adi_En: string;
  Tur: string;
  Barkod: string;
  Miktar: string;
  Birim: string;
  TesteMiktar: string;
  TesteMiktarBirim: string;
  SeriNo: string;
  UretimTarihi: string;
  SKT: string;
  Aciklama: string;
  Urun_Tipi: string;
  UGDTip_ID: number | null;
  Hedef_Grup: string;
  hizmetler: HizmetRow[];
  open: boolean;
  saving: boolean;
  saved: boolean;
  error: string;
}

const GRUPLAR = ["Özel", "K.D."];
const BIRIMLER = ["g", "mL", "L", "Adet"];
const KARALAR = ["Basit Karar Kuralı", "Müşteri Lehine", "Müşteri Aleyhine"];
const DILLER = ["Türkçe", "İngilizce", "Hem Türkçe Hem İngilizce"];

function newCardId() { return `c-${Date.now()}-${Math.random().toString(36).slice(2, 7)}`; }
function newHizmetKey() { return `h-${Date.now()}-${Math.random().toString(36).slice(2, 7)}`; }

function emptyCard(partial: Partial<NumuneCard> = {}): NumuneCard {
  return {
    cardId: newCardId(),
    savedId: null,
    RaporNo: "",
    Numune_Adi: "",
    Numune_Adi_En: "",
    Tur: "",
    Barkod: "",
    Miktar: "",
    Birim: "mL",
    TesteMiktar: "",
    TesteMiktarBirim: "Adet",
    SeriNo: "",
    UretimTarihi: "",
    SKT: "",
    Aciklama: "",
    Urun_Tipi: "",
    UGDTip_ID: null,
    Hedef_Grup: "Yetişkinler",
    hizmetler: [],
    open: true,
    saving: false,
    saved: false,
    error: "",
    ...partial,
  };
}

function normalizePartialDate(v: string): string | null {
  if (!v) return null;
  const parts = v.split("-");
  if (parts.length === 1) return `${parts[0]}-01-01`;
  if (parts.length === 2) return `${parts[0]}-${parts[1]}-01`;
  return v;
}

// ── FirmaSearch typeahead ──────────────────────────────────
function FirmaSearch({ label, value, displayValue, onChange, placeholder }: {
  label: string; value: number | null; displayValue: string;
  onChange: (id: number | null, ad: string) => void; placeholder?: string;
}) {
  const [q, setQ] = useState(displayValue);
  const [results, setRes] = useState<{ ID: number; Ad: string }[]>([]);
  const [open, setOpen] = useState(false);
  const timer = useRef<ReturnType<typeof setTimeout> | null>(null);
  const wrapRef = useRef<HTMLDivElement>(null);

  useEffect(() => { setQ(displayValue); }, [displayValue]);

  useEffect(() => {
    const handler = (e: MouseEvent) => {
      if (wrapRef.current && !wrapRef.current.contains(e.target as Node)) setOpen(false);
    };
    document.addEventListener("mousedown", handler);
    return () => document.removeEventListener("mousedown", handler);
  }, []);

  const search = useCallback((val: string) => {
    if (timer.current) clearTimeout(timer.current);
    timer.current = setTimeout(async () => {
      if (val.trim().length < 1) { setRes([]); setOpen(false); return; }
      try {
        const r = await fetch(`/api/numune-form/firmalar?q=${encodeURIComponent(val)}`);
        const data = await r.json();
        setRes(data); setOpen(data.length > 0);
      } catch { setRes([]); }
    }, 200);
  }, []);

  return (
    <div className={yn.fg} ref={wrapRef} style={{ position: "relative" }}>
      <label>{label}</label>
      <div style={{ position: "relative" }}>
        <input
          value={q}
          placeholder={placeholder || "Yazmaya başlayın…"}
          onChange={e => { setQ(e.target.value); search(e.target.value); if (!e.target.value) onChange(null, ""); }}
          onFocus={() => { if (results.length) setOpen(true); }}
          autoComplete="off"
        />
        {value ? (
          <button type="button"
            onClick={() => { onChange(null, ""); setQ(""); setRes([]); }}
            style={{ position: "absolute", right: 8, top: "50%", transform: "translateY(-50%)", background: "none", border: "none", cursor: "pointer", color: "var(--color-text-tertiary)", fontSize: "0.8rem" }}
          >✕</button>
        ) : null}
      </div>
      {open && results.length > 0 ? (
        <div style={{
          position: "absolute", zIndex: 300, top: "100%", left: 0, right: 0,
          background: "var(--color-surface)", border: "1px solid var(--color-border)",
          borderRadius: "var(--radius-sm)", boxShadow: "0 4px 16px rgba(0,0,0,0.12)",
          maxHeight: 200, overflowY: "auto",
        }}>
          {results.map(r => (
            <div key={r.ID}
              style={{ padding: "8px 12px", cursor: "pointer", fontSize: "0.845rem", borderBottom: "1px solid var(--color-border-light)", background: r.ID === value ? "var(--color-accent-light)" : "transparent" }}
              onMouseDown={() => { onChange(r.ID, r.Ad); setQ(r.Ad); setOpen(false); }}
            >{r.Ad}</div>
          ))}
        </div>
      ) : null}
    </div>
  );
}


// ── Mini hizmet panel ──────────────────────────────────────
function HizmetPanel({ tarih, rows, onChange }: { tarih: string; rows: HizmetRow[]; onChange: (r: HizmetRow[]) => void }) {
  const [q, setQ] = useState("");
  const [opts, setOpts] = useState<any[]>([]);
  const [loading, setLoading] = useState(false);
  const [open, setOpen] = useState(false);
  const timer = useRef<ReturnType<typeof setTimeout> | null>(null);

  const search = (val: string) => {
    setQ(val);
    if (timer.current) clearTimeout(timer.current);
    timer.current = setTimeout(async () => {
      setLoading(true);
      try {
        const r = await fetch(`/api/teklifler/lookup?type=hizmetler&q=${encodeURIComponent(val)}`);
        const j = await r.json();
        setOpts(j.data || []);
        setOpen(true);
      } finally { setLoading(false); }
    }, 300);
  };

  const addHizmet = (h: any) => {
    if (rows.some(x => x.AnalizID === h.ID)) return;
    const base = tarih ? new Date(tarih + "T12:00:00") : new Date();
    base.setDate(base.getDate() + (h.Sure ?? 0));
    const termin = base.toISOString().split("T")[0]!;
    onChange([...rows, { key: newHizmetKey(), AnalizID: h.ID, Termin: termin, x3ID: null, Kod: h.Kod, Ad: h.Ad, Metot: h.Metot ?? "", Sure: h.Sure ?? null }]);
    setQ(""); setOpts([]); setOpen(false);
  };

  const remove = (key: string) => onChange(rows.filter(r => r.key !== key));

  return (
    <div className={yn.hizmetSection}>
      <div className={yn.hizmetSectionTitle}>Hizmetler</div>
      <div style={{ position: "relative", marginBottom: 8 }}>
        <input
          value={q}
          onChange={e => search(e.target.value)}
          placeholder="Hizmet adı veya kodu…"
          style={{ width: "100%", padding: "6px 10px", border: "1px solid var(--color-border)", borderRadius: "var(--radius-sm)", fontSize: "0.8125rem", background: "var(--color-surface)", color: "var(--color-text-primary)", boxSizing: "border-box" }}
        />
        {open && opts.length > 0 && (
          <div style={{ position: "absolute", top: "100%", left: 0, right: 0, zIndex: 200, background: "var(--color-surface)", border: "1px solid var(--color-border)", borderRadius: "var(--radius-sm)", boxShadow: "0 4px 12px rgba(0,0,0,0.1)", maxHeight: 180, overflowY: "auto" }}>
            {loading ? <div style={{ padding: "8px 12px", fontSize: "0.8rem", color: "var(--color-text-tertiary)" }}>Yükleniyor…</div> : opts.map(h => (
              <div key={h.ID}
                style={{ display: "flex", justifyContent: "space-between", alignItems: "center", padding: "7px 12px", cursor: "pointer", fontSize: "0.8125rem", borderBottom: "1px solid var(--color-border-light)" }}
                onMouseDown={() => addHizmet(h)}
                onMouseEnter={e => (e.currentTarget.style.background = "var(--color-surface-2)")}
                onMouseLeave={e => (e.currentTarget.style.background = "transparent")}
              >
                <span><strong style={{ color: "var(--color-text-tertiary)", marginRight: 6 }}>{h.Kod}</strong>{h.Ad}</span>
                <span style={{ fontSize: "0.75rem", color: "var(--color-text-tertiary)", marginLeft: 8, flexShrink: 0 }}>{h.Sure ? `${h.Sure} g` : ""}</span>
              </div>
            ))}
          </div>
        )}
      </div>
      {rows.length > 0 && (
        <table style={{ width: "100%", borderCollapse: "collapse", fontSize: "0.8rem" }}>
          <thead>
            <tr style={{ borderBottom: "1px solid var(--color-border-light)" }}>
              <th style={{ textAlign: "left", padding: "4px 8px", fontWeight: 600, color: "var(--color-text-secondary)", fontSize: "0.72rem", textTransform: "uppercase" }}>Kod</th>
              <th style={{ textAlign: "left", padding: "4px 8px", fontWeight: 600, color: "var(--color-text-secondary)", fontSize: "0.72rem", textTransform: "uppercase" }}>Hizmet</th>
              <th style={{ textAlign: "left", padding: "4px 8px", fontWeight: 600, color: "var(--color-text-secondary)", fontSize: "0.72rem", textTransform: "uppercase", width: 140 }}>Termin</th>
              <th style={{ width: 32 }} />
            </tr>
          </thead>
          <tbody>
            {rows.map(r => (
              <tr key={r.key} style={{ borderBottom: "1px solid var(--color-border-light)" }}>
                <td style={{ padding: "5px 8px", color: "var(--color-text-tertiary)", fontVariantNumeric: "tabular-nums" }}>{r.Kod}</td>
                <td style={{ padding: "5px 8px" }}>{r.Ad}</td>
                <td style={{ padding: "5px 8px" }}>
                  <input type="date" value={r.Termin?.slice(0,10) || ""} onChange={e => onChange(rows.map(x => x.key === r.key ? {...x, Termin: e.target.value} : x))} style={{ width: "100%", padding: "3px 6px", border: "1px solid var(--color-border)", borderRadius: 4, fontSize: "0.8rem", background: "var(--color-surface)" }} />
                </td>
                <td style={{ padding: "5px 4px" }}>
                  <button type="button" onClick={() => remove(r.key)} style={{ background: "none", border: "none", cursor: "pointer", color: "var(--color-text-tertiary)", fontSize: "0.85rem", padding: 2 }}>✕</button>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      )}
    </div>
  );
}

// ── Ana bileşen ────────────────────────────────────────────
export default function YeniNumuneClient() {
  const today = new Date().toISOString().split("T")[0]!;

  const [evrak, setEvrak] = useState<EvrakForm>({
    Tarih: today, Evrak_No: "", Teklif_No: "", Talep_No: "",
    Karar: "Basit Karar Kuralı", Dil: "Türkçe",
    Firma_ID: null, FirmaAd: "", ProjeID: null, ProjeAd: "", Grup: "Özel",
  });
  const [evrakOpen, setEvrakOpen] = useState(true);
  const [evrakSaved, setEvrakSaved] = useState(false);
  const [loadingNos, setLoadingNos] = useState(false);

  const [numuneler, setNumuneler] = useState<NumuneCard[]>([]);
  const [lookup, setLookup] = useState<LookupData>({ grupTurleri: [], rUGDTipler: [], paketler: [] });

  // Load lookup data
  useEffect(() => {
    fetch("/api/numune-form/lookup").then(r => r.json()).then((d: LookupData) => { if (d.grupTurleri) setLookup(d); }).catch(() => {});
  }, []);

  // Auto-fill Evrak_No when Grup changes (if not yet filled)
  useEffect(() => {
    if (!evrak.Grup || evrak.Evrak_No) return;
    let cancelled = false;
    (async () => {
      setLoadingNos(true);
      try {
        const r = await fetch(`/api/numune-form/next-no?grup=${encodeURIComponent(evrak.Grup)}`);
        const j = await r.json();
        if (!cancelled && r.ok) setEvrak(e => ({ ...e, Evrak_No: j.evrakNo }));
      } finally { if (!cancelled) setLoadingNos(false); }
    })();
    return () => { cancelled = true; };
  }, [evrak.Grup]);

  const patchEvrak = (u: Partial<EvrakForm>) => setEvrak(e => ({ ...e, ...u }));

  // Fetch next Rapor No for a new card
  const fetchNextRaporNo = async (): Promise<string> => {
    try {
      const r = await fetch(`/api/numune-form/next-no?grup=${encodeURIComponent(evrak.Grup || "Özel")}`);
      const j = await r.json();
      return r.ok ? j.raporNo : "";
    } catch { return ""; }
  };

  const addNumune = async () => {
    const raporNo = await fetchNextRaporNo();
    const card = emptyCard({ RaporNo: raporNo, Tur: "" });
    setNumuneler(prev => [...prev, card]);
  };

  const patchCard = (cardId: string, update: Partial<NumuneCard>) => {
    setNumuneler(prev => prev.map(c => c.cardId === cardId ? { ...c, ...update } : c));
  };

  const removeCard = (cardId: string) => {
    setNumuneler(prev => prev.filter(c => c.cardId !== cardId));
  };

  const saveCard = async (card: NumuneCard) => {
    if (!card.Numune_Adi.trim()) { patchCard(card.cardId, { error: "Numune Adı zorunludur." }); return; }
    if (!card.RaporNo.trim()) { patchCard(card.cardId, { error: "Rapor No zorunludur." }); return; }
    if (!evrak.Evrak_No.trim()) { patchCard(card.cardId, { error: "Önce Evrak No girin." }); return; }

    patchCard(card.cardId, { saving: true, error: "" });

    const body = {
      nkr: {
        Tarih: evrak.Tarih || null,
        Barkod: card.Barkod || null,
        Teklif_No: evrak.Teklif_No || null,
        Talep_No: evrak.Talep_No || null,
        Evrak_No: evrak.Evrak_No.trim(),
        RaporNo: card.RaporNo.trim(),
        Revno: "0",
        Grup: evrak.Grup || null,
        Tur: card.Tur || null,
        Karar: evrak.Karar || null,
        Dil: evrak.Dil || null,
        Firma_ID: evrak.Firma_ID,
        Numune_Adi: card.Numune_Adi.trim(),
        Numune_Adi_En: card.Numune_Adi_En || null,
        Urun_Tipi: card.Urun_Tipi || null,
        UGDTip_ID: card.UGDTip_ID,
        Hedef_Grup: card.Hedef_Grup || null,
        TesteMiktar: card.TesteMiktar || null,
        TesteMiktarBirim: card.TesteMiktarBirim || null,
        Aciklama: card.Aciklama || null,
      },
      detay: {
        ProjeID: evrak.ProjeID,
        Miktar: card.Miktar || null,
        Birim: card.Birim || null,
        SeriNo: card.SeriNo || null,
        UretimTarihi: normalizePartialDate(card.UretimTarihi),
        SKT: normalizePartialDate(card.SKT),
      },
      hizmetler: card.hizmetler.map(h => ({ AnalizID: h.AnalizID, Termin: h.Termin || null, x3ID: h.x3ID })),
      formul: [],
    };

    const url = card.savedId ? `/api/numune-form/${card.savedId}` : "/api/numune-form";
    const method = card.savedId ? "PUT" : "POST";

    try {
      const res = await fetch(url, { method, headers: { "Content-Type": "application/json" }, body: JSON.stringify(body) });
      const data = await res.json().catch(() => ({}));
      if (!res.ok) throw new Error(data.error || "Kaydedilemedi");
      const newSavedId = card.savedId ?? (data.id as number);
      patchCard(card.cardId, { saving: false, saved: true, savedId: newSavedId, open: false });
      setEvrakSaved(true);
    } catch (e: any) {
      patchCard(card.cardId, { saving: false, error: e.message || "Hata" });
    }
  };

  const turler = evrak.Grup
    ? lookup.grupTurleri.filter(g => g.Grup === evrak.Grup).map(g => g.Tur)
    : [];

  const sel: React.CSSProperties = { width: "100%" };

  return (
    <div className={yn.page}>
      {/* Toolbar */}
      <div className={yn.toolbar}>
        <div>
          <div className={yn.title}>Yeni Numune Girişi <span style={{ fontSize: "0.7rem", verticalAlign: "middle", padding: "2px 8px", background: "#0071e320", color: "#0071e3", borderRadius: 8, marginLeft: 6 }}>Önizleme</span></div>
          <div className={yn.subtitle}>Tek evrak için birden fazla numune ekleyebilirsiniz.</div>
        </div>
        <Link href="/laboratuvar/numune-takip" className={yn.backLink}>← Listeye dön</Link>
      </div>

      {/* ── Evrak Bilgileri ── */}
      <div className={yn.evrakCard}>
        <div
          className={`${yn.evrakCardHead} ${evrakOpen ? yn.open : ""}`}
          onClick={() => setEvrakOpen(o => !o)}
        >
          <div className={yn.evrakCardTitle}>
            <svg viewBox="0 0 20 20" fill="currentColor" width="14" height="14" style={{ color: "var(--color-text-tertiary)", transform: evrakOpen ? "rotate(90deg)" : "rotate(0deg)", transition: "transform 0.15s" }}>
              <path fillRule="evenodd" d="M7.21 14.77a.75.75 0 0 1 .02-1.06L11.168 10 7.23 6.29a.75.75 0 1 1 1.04-1.08l4.5 4.25a.75.75 0 0 1 0 1.08l-4.5 4.25a.75.75 0 0 1-1.06-.02Z" clipRule="evenodd" />
            </svg>
            Evrak Bilgileri
          </div>
          {!evrakOpen && evrakSaved && (
            <div className={yn.evrakSummary}>
              {evrak.FirmaAd && <span className={yn.evrakSummaryItem}><span className={yn.evrakSummaryLabel}>Firma:</span> <strong>{evrak.FirmaAd}</strong></span>}
              {evrak.Evrak_No && <span className={yn.evrakSummaryItem}><span className={yn.evrakSummaryLabel}>Evrak:</span> <strong>{evrak.Evrak_No}</strong></span>}
              {evrak.Grup && <span className={yn.evrakSummaryItem}><span className={yn.evrakSummaryLabel}>Grup:</span> <strong>{evrak.Grup}</strong></span>}
            </div>
          )}
        </div>

        {evrakOpen && (
          <div className={yn.evrakBody}>
            <div className={yn.evrakGrid}>
              <div className={yn.fg}>
                <label>Tarih</label>
                <input type="date" style={sel} value={evrak.Tarih} onChange={e => patchEvrak({ Tarih: e.target.value })} />
              </div>
              <div className={yn.fg}>
                <label>Ürün grubu</label>
                <select style={sel} value={evrak.Grup} onChange={e => patchEvrak({ Grup: e.target.value })}>
                  {GRUPLAR.map(g => <option key={g} value={g}>{g}</option>)}
                </select>
              </div>
              <div className={yn.fg}>
                <label>Evrak No {loadingNos && <span style={{ fontWeight: 400, color: "var(--color-text-tertiary)", fontSize: "0.7rem" }}>…</span>}</label>
                <input style={sel} value={evrak.Evrak_No} onChange={e => patchEvrak({ Evrak_No: e.target.value })} />
              </div>
              <div className={yn.fg}>
                <label>Teklif No</label>
                <input style={sel} value={evrak.Teklif_No} onChange={e => patchEvrak({ Teklif_No: e.target.value })} />
              </div>
              <div className={yn.fg}>
                <label>Talep No</label>
                <input style={sel} value={evrak.Talep_No} onChange={e => patchEvrak({ Talep_No: e.target.value })} />
              </div>
            </div>
            <div className={yn.evrakGrid2}>
              <FirmaSearch label="Firma" value={evrak.Firma_ID} displayValue={evrak.FirmaAd} onChange={(id, ad) => patchEvrak({ Firma_ID: id, FirmaAd: ad })} placeholder="Firma adı…" />
              <FirmaSearch label="Proje" value={evrak.ProjeID} displayValue={evrak.ProjeAd} onChange={(id, ad) => patchEvrak({ ProjeID: id, ProjeAd: ad })} placeholder="Proje adı…" />
              <div className={yn.fg}>
                <label>Karar kuralı</label>
                <select style={sel} value={evrak.Karar} onChange={e => patchEvrak({ Karar: e.target.value })}>
                  {KARALAR.map(k => <option key={k} value={k}>{k}</option>)}
                </select>
              </div>
              <div className={yn.fg}>
                <label>Raporlama dili</label>
                <select style={sel} value={evrak.Dil} onChange={e => patchEvrak({ Dil: e.target.value })}>
                  {DILLER.map(d => <option key={d} value={d}>{d}</option>)}
                </select>
              </div>
            </div>
            <div style={{ display: "flex", justifyContent: "flex-end" }}>
              <button
                type="button"
                style={{ padding: "6px 16px", background: "var(--color-surface-2)", border: "1px solid var(--color-border)", borderRadius: "var(--radius-sm)", fontSize: "0.8125rem", cursor: "pointer", fontWeight: 500 }}
                onClick={() => { setEvrakOpen(false); setEvrakSaved(true); }}
              >
                Tamam, numune ekle →
              </button>
            </div>
          </div>
        )}
      </div>

      {/* ── Numune listesi ── */}
      <div className={yn.numuneListHeader}>
        <div className={yn.numuneListTitle}>
          Numuneler
          {numuneler.length > 0 && (
            <span style={{ marginLeft: 8, padding: "2px 9px", background: "var(--color-accent-light)", color: "var(--color-accent)", borderRadius: 10, fontSize: "0.72rem", fontWeight: 600 }}>
              {numuneler.length}
            </span>
          )}
        </div>
        <button type="button" className={yn.addBtn} onClick={() => void addNumune()}>
          <svg viewBox="0 0 20 20" fill="currentColor" width="14" height="14">
            <path d="M10.75 4.75a.75.75 0 0 0-1.5 0v4.5h-4.5a.75.75 0 0 0 0 1.5h4.5v4.5a.75.75 0 0 0 1.5 0v-4.5h4.5a.75.75 0 0 0 0-1.5h-4.5v-4.5Z" />
          </svg>
          Numune Ekle
        </button>
      </div>

      {numuneler.length === 0 && (
        <div style={{ textAlign: "center", padding: "40px 20px", background: "var(--color-surface)", border: "2px dashed var(--color-border-light)", borderRadius: "var(--radius-md)", color: "var(--color-text-tertiary)", fontSize: "0.845rem" }}>
          Henüz numune eklenmedi. Yukarıdaki "+ Numune Ekle" butonunu kullanın.
        </div>
      )}

      {numuneler.map((card) => {
        const cardTurler = evrak.Grup ? lookup.grupTurleri.filter(g => g.Grup === evrak.Grup).map(g => g.Tur) : [];
        return (
          <div key={card.cardId} className={yn.numuneCard}>
            {/* Kart başlığı */}
            <div
              className={`${yn.numuneCardHead} ${card.open ? yn.open : ""}`}
              onClick={() => patchCard(card.cardId, { open: !card.open })}
            >
              <svg viewBox="0 0 20 20" fill="currentColor" width="12" height="12" style={{ color: "var(--color-text-tertiary)", flexShrink: 0, transform: card.open ? "rotate(90deg)" : "rotate(0deg)", transition: "transform 0.15s" }}>
                <path fillRule="evenodd" d="M7.21 14.77a.75.75 0 0 1 .02-1.06L11.168 10 7.23 6.29a.75.75 0 1 1 1.04-1.08l4.5 4.25a.75.75 0 0 1 0 1.08l-4.5 4.25a.75.75 0 0 1-1.06-.02Z" clipRule="evenodd" />
              </svg>
              {card.RaporNo
                ? <span className={yn.numuneRaporNo}>{card.RaporNo}</span>
                : <span className={yn.numuneRaporNoEmpty}>Rapor No…</span>
              }
              <span className={yn.numuneAd}>{card.Numune_Adi || <span style={{ color: "var(--color-text-tertiary)", fontStyle: "italic" }}>Numune adı girilmedi</span>}</span>
              {[evrak.Grup, card.Tur].filter(Boolean).length > 0 && (
                <span className={yn.numuneGrupTur}>{[evrak.Grup, card.Tur].filter(Boolean).join(" / ")}</span>
              )}
              {card.hizmetler.length > 0 && (
                <span className={yn.numuneBadge}>{card.hizmetler.length} hizmet</span>
              )}
              {card.saved && !card.open && (
                <span className={yn.savedBadge}>✓ Kaydedildi</span>
              )}
            </div>

            {/* Kart gövdesi */}
            {card.open && (
              <div className={yn.numuneCardBody}>
                {card.error && <div className={yn.cardErr}>{card.error}</div>}

                {/* İlk satır: Rapor No + Numune Adı TR + Numune Adı EN + Tür */}
                <div className={yn.numuneInfoGrid}>
                  <div className={yn.fg}>
                    <label>Numune Adı (TR) *</label>
                    <input style={sel} value={card.Numune_Adi} onChange={e => patchCard(card.cardId, { Numune_Adi: e.target.value })} placeholder="Türkçe ad…" />
                  </div>
                  <div className={yn.fg}>
                    <label>Numune Adı (EN)</label>
                    <input style={sel} value={card.Numune_Adi_En} onChange={e => patchCard(card.cardId, { Numune_Adi_En: e.target.value })} placeholder="English name…" />
                  </div>
                  <div className={yn.fg}>
                    <label>Rapor No *</label>
                    <input style={sel} value={card.RaporNo} onChange={e => patchCard(card.cardId, { RaporNo: e.target.value })} />
                  </div>
                  <div className={yn.fg}>
                    <label>Ürün türü</label>
                    <select style={sel} value={card.Tur} onChange={e => patchCard(card.cardId, { Tur: e.target.value })} disabled={cardTurler.length === 0}>
                      <option value="">Seçin</option>
                      {cardTurler.map(t => <option key={t} value={t}>{t}</option>)}
                    </select>
                  </div>
                </div>

                {/* İkinci satır: Barkod + Nominal + Teste + Seri + ÜretimTarihi + SKT */}
                <div className={yn.numuneInfoGrid2}>
                  <div className={yn.fg}>
                    <label>Barkod</label>
                    <input style={sel} value={card.Barkod} onChange={e => patchCard(card.cardId, { Barkod: e.target.value })} />
                  </div>
                  <div className={yn.fg}>
                    <label>Nominal miktar</label>
                    <div style={{ display: "flex", gap: 4 }}>
                      <input type="number" min={0} placeholder="0" value={card.Miktar} onChange={e => patchCard(card.cardId, { Miktar: e.target.value })} style={{ flex: 1, padding: "7px 8px", border: "1px solid var(--color-border)", borderRadius: "var(--radius-sm)", fontSize: "0.8375rem", background: "var(--color-surface)", minWidth: 0 }} />
                      <select value={card.Birim} onChange={e => patchCard(card.cardId, { Birim: e.target.value })} style={{ width: 62, padding: "7px 4px", border: "1px solid var(--color-border)", borderRadius: "var(--radius-sm)", fontSize: "0.8125rem", background: "var(--color-surface)" }}>
                        <option value="">—</option>
                        {BIRIMLER.map(b => <option key={b} value={b}>{b}</option>)}
                      </select>
                    </div>
                  </div>
                  <div className={yn.fg}>
                    <label>Teste gelen miktar</label>
                    <div style={{ display: "flex", gap: 4 }}>
                      <input type="number" min={0} placeholder="0" value={card.TesteMiktar} onChange={e => patchCard(card.cardId, { TesteMiktar: e.target.value })} style={{ flex: 1, padding: "7px 8px", border: "1px solid var(--color-border)", borderRadius: "var(--radius-sm)", fontSize: "0.8375rem", background: "var(--color-surface)", minWidth: 0 }} />
                      <select value={card.TesteMiktarBirim} onChange={e => patchCard(card.cardId, { TesteMiktarBirim: e.target.value })} style={{ width: 62, padding: "7px 4px", border: "1px solid var(--color-border)", borderRadius: "var(--radius-sm)", fontSize: "0.8125rem", background: "var(--color-surface)" }}>
                        <option value="">—</option>
                        {BIRIMLER.map(b => <option key={b} value={b}>{b}</option>)}
                      </select>
                    </div>
                  </div>
                  <div className={yn.fg}>
                    <label>Seri / Lot</label>
                    <input style={sel} value={card.SeriNo} onChange={e => patchCard(card.cardId, { SeriNo: e.target.value })} />
                  </div>
                  <div className={yn.fg}>
                    <label>Üretim tarihi</label>
                    <PartialDateInput value={card.UretimTarihi} onChange={v => patchCard(card.cardId, { UretimTarihi: v })} />
                  </div>
                  <div className={yn.fg}>
                    <label>SKT</label>
                    <PartialDateInput value={card.SKT} onChange={v => patchCard(card.cardId, { SKT: v })} />
                  </div>
                </div>

                {/* Hizmetler */}
                <HizmetPanel
                  tarih={evrak.Tarih}
                  rows={card.hizmetler}
                  onChange={rows => patchCard(card.cardId, { hizmetler: rows })}
                />

                {/* Footer */}
                <div className={yn.numuneCardFooter}>
                  <button type="button" className={yn.deleteCardBtn} onClick={() => removeCard(card.cardId)} disabled={card.saving}>
                    Kartı Kaldır
                  </button>
                  <button type="button" className={yn.saveCardBtn} onClick={() => void saveCard(card)} disabled={card.saving}>
                    {card.saving ? "Kaydediliyor…" : card.savedId ? "Güncelle" : "Kaydet"}
                  </button>
                </div>
              </div>
            )}
          </div>
        );
      })}
    </div>
  );
}

"use client";

import { useState, useEffect, useCallback, useRef } from "react";
import { useRouter } from "next/navigation";
import styles from "@/app/styles/table.module.css";

// ── Tipler ──────────────────────────────────────────────────────
interface NumuneItem {
  ID: number;
  Evrak_No: string;
  RaporNo: string;
  Numune_Adi: string;
  Grup: string | null;
  Tur: string | null;
}

interface EvrakGroup {
  evrakNo: string;
  tarih: string | null;
  firmaAd: string | null;
  projeAd: string | null;
  numuneSayisi: number;
  odemeDurumu: string | null;
  numuneler: NumuneItem[];
}

// Fatura kesilmiş = yalnızca bu iki durum; diğerleri (null dahil) → Faturalandır aktif
const isFaturali = (d: string | null) => d === "Ödendi" || d === "Bekliyor";

// ── Yardımcı bileşenler ──────────────────────────────────────────
function OdemeBadge({ durum }: { durum: string | null }) {
  if (!durum) return (
    <span style={{
      display: "inline-block", padding: "2px 9px", borderRadius: 10,
      fontSize: "0.72rem", fontWeight: 600, background: "#8e8e9318", color: "#636366",
    }}>Fatura Kesilmedi</span>
  );
  const map: Record<string, { bg: string; fg: string }> = {
    "Ödendi":   { bg: "#34c75918", fg: "#248a3d" },
    "Bekliyor": { bg: "#ff950018", fg: "#c06800" },
  };
  const c = map[durum] ?? { bg: "#8e8e9318", fg: "#636366" };
  return (
    <span style={{
      display: "inline-block", padding: "2px 9px", borderRadius: 10,
      fontSize: "0.72rem", fontWeight: 600, background: c.bg, color: c.fg,
    }}>{durum}</span>
  );
}

function NumuneBadge({ count }: { count: number }) {
  return (
    <span style={{
      display: "inline-flex", alignItems: "center", gap: 3,
      padding: "2px 8px", borderRadius: 10, fontSize: "0.72rem", fontWeight: 600,
      background: "var(--color-accent-light)", color: "var(--color-accent)",
    }}>
      {count}
    </span>
  );
}

// ── Ana bileşen ─────────────────────────────────────────────────
export default function NumuneKabulTable() {
  const router = useRouter();
  const [groups, setGroups]         = useState<EvrakGroup[]>([]);
  const [total, setTotal]           = useState(0);
  const [page, setPage]             = useState(1);
  const [limit, setLimit]           = useState(20);
  const [totalPages, setTotalPages] = useState(1);
  const [search, setSearch]         = useState("");
  const [loading, setLoading]       = useState(true);
  const [transitioning, setTransitioning] = useState(false); // sayfa geçişi (skeleton değil, overlay)
  const [error, setError]           = useState("");

  // Accordion
  const [openGroups, setOpenGroups] = useState<Set<string>>(new Set());

  const [deleteId, setDeleteId]   = useState<number | null>(null);
  const [deleting, setDeleting]   = useState(false);

  const [selectedIds, setSelectedIds]       = useState<Set<number>>(new Set());
  const [printMenuEvrak, setPrintMenuEvrak] = useState<string | null>(null);

  const toggleSelect = (id: number) =>
    setSelectedIds(prev => { const n = new Set(prev); n.has(id) ? n.delete(id) : n.add(id); return n; });

  const groupSelectedIds = (numuneler: NumuneItem[]) =>
    numuneler.filter(n => selectedIds.has(n.ID)).map(n => n.ID);

  const handlePrint = (ids: number[], lang: "tr" | "en") => {
    window.open(`/laboratuvar/rapor-yazdir?ids=${ids.join(",")}&lang=${lang}`, "_blank", "noopener,noreferrer");
    setPrintMenuEvrak(null);
  };

  const searchTimer = useRef<ReturnType<typeof setTimeout> | null>(null);
  const abortRef    = useRef<AbortController | null>(null);
  const latestReqId = useRef(0); // monotone artan — yalnızca son istek geçerli
  const didMount    = useRef(false); // sayfa/limit effect'i mount'ta çalışmasın

  // ── Veri çekme ──────────────────────────────────────────────
  const fetchData = useCallback(async (
    p: number, s: string, l: number,
    opts: { clearFirst?: boolean } = {}
  ) => {
    // Her çağrıya benzersiz ID ver; yalnızca en son ID'li yanıt işlenir
    const reqId = ++latestReqId.current;

    if (abortRef.current) abortRef.current.abort();
    const ctrl = new AbortController();
    abortRef.current = ctrl;

    if (opts.clearFirst) {
      // Arama: eski grupları temizle + skeleton göster
      setGroups([]);
      setLoading(true);
      setTransitioning(false);
    } else {
      // Sayfa/limit geçişi: eski grupları koru, hafif overlay
      setTransitioning(true);
      setLoading(false);
    }
    setError("");

    try {
      const res = await fetch(
        `/api/numune-kabul?page=${p}&limit=${l}&search=${encodeURIComponent(s)}`,
        { signal: ctrl.signal }
      );

      // Eski istek tamamlandıysa yoksay
      if (reqId !== latestReqId.current) return;

      if (!res.ok) throw new Error((await res.json()).error || "Hata");
      const json = await res.json();

      setGroups(json.data);
      setTotal(json.total);
      setTotalPages(json.totalPages);
    } catch (e: any) {
      if (e.name === "AbortError" || reqId !== latestReqId.current) return;
      setError(e.message);
    } finally {
      if (reqId === latestReqId.current) {
        setLoading(false);
        setTransitioning(false);
      }
    }
  }, []);

  // İlk yükleme — bir kez çalışır
  useEffect(() => {
    fetchData(1, "", limit, { clearFirst: true });
  }, []);

  // Sayfa / limit değişimi — mount sonrası her değişimde çalışır
  useEffect(() => {
    if (!didMount.current) { didMount.current = true; return; }
    fetchData(page, search, limit, { clearFirst: false });
  }, [page, limit]);

  const handleSearch = (val: string) => {
    setSearch(val);
    if (searchTimer.current) clearTimeout(searchTimer.current);
    searchTimer.current = setTimeout(() => {
      setPage(1);
      fetchData(1, val, limit, { clearFirst: true });
    }, 200);
  };

  // ── Accordion ───────────────────────────────────────────────
  const toggleGroup = (evrakNo: string) => {
    setOpenGroups(prev => {
      const next = new Set(prev);
      next.has(evrakNo) ? next.delete(evrakNo) : next.add(evrakNo);
      return next;
    });
  };

  const handleDelete = async () => {
    if (!deleteId) return;
    setDeleting(true);
    try {
      const res = await fetch(`/api/numune-kabul/${deleteId}`, { method: "DELETE" });
      if (!res.ok) throw new Error((await res.json()).error || "Silinemedi");
      setDeleteId(null);
      fetchData(page, search, limit, { clearFirst: false });
    } catch (e: any) { setError(e.message); }
    finally { setDeleting(false); }
  };

  const openNew = () => { router.push("/laboratuvar/numune-form"); };
  const openEdit = (n: NumuneItem) => {
    window.open(`/laboratuvar/numune-form/${n.ID}`, "_blank", "noopener,noreferrer");
  };

  // ── Sayfalama ────────────────────────────────────────────────
  const goTo = (p: number) => { if (p >= 1 && p <= totalPages) setPage(p); };
  const pageNums = () => {
    const nums: (number | "…")[] = [];
    if (totalPages <= 7) { for (let i = 1; i <= totalPages; i++) nums.push(i); }
    else {
      nums.push(1);
      if (page > 3) nums.push("…");
      for (let i = Math.max(2, page - 1); i <= Math.min(totalPages - 1, page + 1); i++) nums.push(i);
      if (page < totalPages - 2) nums.push("…");
      nums.push(totalPages);
    }
    return nums;
  };

  const formatTarih = (t: string | null) => {
    if (!t) return "—";
    const [y, m, d] = t.split("-");
    return `${d}.${m}.${y}`;
  };

  // ── Render ───────────────────────────────────────────────────
  return (
    <>
      {/* ── Toolbar ── */}
      <div className={styles.toolbar}>
        <div className={styles.toolbarLeft}>
          <div className={styles.searchBox} style={{ width: 340 }}>
            <svg className={styles.searchIcon} viewBox="0 0 20 20" fill="currentColor" width="15" height="15">
              <path fillRule="evenodd" d="M9 3.5a5.5 5.5 0 1 0 0 11 5.5 5.5 0 0 0 0-11ZM2 9a7 7 0 1 1 12.452 4.391l3.328 3.329a.75.75 0 1 1-1.06 1.06l-3.329-3.328A7 7 0 0 1 2 9Z" clipRule="evenodd" />
            </svg>
            <input
              className={styles.searchInput}
              placeholder="Evrak no, rapor no, firma, numune adı…"
              value={search}
              onChange={e => handleSearch(e.target.value)}
            />
            {search && (
              <button className={styles.searchClear} onClick={() => handleSearch("")}>
                <svg viewBox="0 0 20 20" fill="currentColor" width="14" height="14">
                  <path d="M6.28 5.22a.75.75 0 0 0-1.06 1.06L8.94 10l-3.72 3.72a.75.75 0 1 0 1.06 1.06L10 11.06l3.72 3.72a.75.75 0 1 0 1.06-1.06L11.06 10l3.72-3.72a.75.75 0 0 0-1.06-1.06L10 8.94 6.28 5.22Z" />
                </svg>
              </button>
            )}
          </div>
          <span className={styles.totalCount}>{total} evrak</span>
        </div>
        <div className={styles.toolbarRight}>
          <select className={styles.pageSizeSelect} value={limit}
            onChange={e => { setLimit(Number(e.target.value)); setPage(1); }}>
            {[10, 20, 50].map(n => <option key={n} value={n}>{n} / sayfa</option>)}
          </select>
          <button className={styles.addBtn} onClick={openNew}>
            <svg viewBox="0 0 20 20" fill="currentColor" width="15" height="15">
              <path d="M10.75 4.75a.75.75 0 0 0-1.5 0v4.5h-4.5a.75.75 0 0 0 0 1.5h4.5v4.5a.75.75 0 0 0 1.5 0v-4.5h4.5a.75.75 0 0 0 0-1.5h-4.5v-4.5Z" />
            </svg>
            Yeni Numune
          </button>
        </div>
      </div>

      {/* ── Accordion listesi ── */}
      <div
        className={styles.tableCard}
        style={{ position: "relative", opacity: transitioning ? 0.55 : 1, transition: "opacity 0.15s" }}
      >
        {error && <div className={styles.errorBar}>{error}</div>}

        {/* ── Kolon başlıkları ── */}
        <div style={{
          display: "flex", alignItems: "center", gap: 0,
          padding: "8px 16px",
          borderBottom: "1px solid var(--color-border-light)",
          background: "var(--color-surface)",
        }}>
          <div style={{ width: 24 }} /> {/* chevron */}
          <div style={{ width: 88,  fontSize: "0.7rem", fontWeight: 600, textTransform: "uppercase", letterSpacing: "0.06em", color: "var(--color-text-tertiary)" }}>Tarih</div>
          <div style={{ width: 130, fontSize: "0.7rem", fontWeight: 600, textTransform: "uppercase", letterSpacing: "0.06em", color: "var(--color-text-tertiary)" }}>Evrak No</div>
          <div style={{ flex: 1,    fontSize: "0.7rem", fontWeight: 600, textTransform: "uppercase", letterSpacing: "0.06em", color: "var(--color-text-tertiary)" }}>Firma / Proje</div>
          <div style={{ width: 64,  fontSize: "0.7rem", fontWeight: 600, textTransform: "uppercase", letterSpacing: "0.06em", color: "var(--color-text-tertiary)", textAlign: "center" }}>Numune</div>
          <div style={{ width: 136,  fontSize: "0.7rem", fontWeight: 600, textTransform: "uppercase", letterSpacing: "0.06em", color: "var(--color-text-tertiary)", textAlign: "center" }}>Ödeme</div>
          <div style={{ width: 36,  fontSize: "0.7rem", fontWeight: 600, textTransform: "uppercase", letterSpacing: "0.06em", color: "var(--color-text-tertiary)", textAlign: "center" }}>Fatura</div>
        </div>

        {/* Skeleton */}
        {loading && (
          <div style={{ padding: "6px 0" }}>
            {Array.from({ length: 6 }).map((_, i) => (
              <div key={i} style={{
                display: "flex", alignItems: "center", gap: 12,
                padding: "14px 20px",
                borderBottom: "1px solid var(--color-border-light)",
              }}>
                <span className={styles.skeleton} style={{ width: 14, height: 14, borderRadius: 3 }} />
                <span className={styles.skeleton} style={{ width: 80 }} />
                <span className={styles.skeleton} style={{ width: 110 }} />
                <span className={styles.skeleton} style={{ flex: 1 }} />
                <span className={styles.skeleton} style={{ width: 60 }} />
                <span className={styles.skeleton} style={{ width: 70 }} />
                <span className={styles.skeleton} style={{ width: 28, height: 28, borderRadius: 6 }} />
              </div>
            ))}
          </div>
        )}

        {/* Boş */}
        {!loading && groups.length === 0 && (
          <div className={styles.empty}>
            <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5" width="36" height="36">
              <path strokeLinecap="round" strokeLinejoin="round" d="M9.75 9.75l4.5 4.5m0-4.5l-4.5 4.5M21 12a9 9 0 1 1-18 0 9 9 0 0 1 18 0Z" />
            </svg>
            Kayıt bulunamadı
          </div>
        )}

        {/* Accordion grupları */}
        {!loading && groups.map((group, gi) => {
          const isOpen = openGroups.has(group.evrakNo);
          return (
            <div
              key={group.evrakNo}
              style={{ borderBottom: gi < groups.length - 1 ? "1px solid var(--color-border-light)" : "none" }}
            >
              {/* ── Grup başlık satırı ── */}
              <div
                style={{
                  display: "flex", alignItems: "center", gap: 0,
                  padding: "12px 16px",
                  cursor: "pointer",
                  background: isOpen ? "var(--color-surface-2)" : "transparent",
                  transition: "background 0.12s",
                  userSelect: "none",
                }}
                onClick={() => toggleGroup(group.evrakNo)}
              >
                {/* Chevron */}
                <div style={{ width: 24, flexShrink: 0, display: "flex", alignItems: "center" }}>
                  <svg
                    viewBox="0 0 20 20" fill="currentColor" width="14" height="14"
                    style={{
                      color: "var(--color-text-tertiary)",
                      transform: isOpen ? "rotate(90deg)" : "rotate(0deg)",
                      transition: "transform 0.18s ease",
                    }}
                  >
                    <path fillRule="evenodd" d="M7.21 14.77a.75.75 0 0 1 .02-1.06L11.168 10 7.23 6.29a.75.75 0 1 1 1.04-1.08l4.5 4.25a.75.75 0 0 1 0 1.08l-4.5 4.25a.75.75 0 0 1-1.06-.02Z" clipRule="evenodd" />
                  </svg>
                </div>

                {/* Tarih */}
                <div style={{ width: 88, flexShrink: 0, fontSize: "0.8rem", color: "var(--color-text-secondary)", fontVariantNumeric: "tabular-nums" }}>
                  {formatTarih(group.tarih)}
                </div>

                {/* Evrak No */}
                <div style={{ width: 130, flexShrink: 0, fontWeight: 700, fontSize: "0.845rem", color: "var(--color-text-primary)", fontVariantNumeric: "tabular-nums" }}>
                  {group.evrakNo}
                </div>

                {/* Firma / Proje */}
                <div style={{ flex: 1, minWidth: 0, overflow: "hidden" }}>
                  <div style={{
                    fontWeight: 500, fontSize: "0.845rem", color: "var(--color-text-primary)",
                    whiteSpace: "nowrap", overflow: "hidden", textOverflow: "ellipsis",
                  }}>{group.firmaAd ?? "—"}</div>
                  {group.projeAd && (
                    <div style={{
                      fontSize: "0.77rem", color: "var(--color-text-tertiary)",
                      whiteSpace: "nowrap", overflow: "hidden", textOverflow: "ellipsis",
                    }}>{group.projeAd}</div>
                  )}
                </div>

                {/* Numune sayısı */}
                <div style={{ width: 64, display: "flex", justifyContent: "center" }}>
                  <NumuneBadge count={group.numuneSayisi} />
                </div>

                {/* Ödeme */}
                <div style={{ width: 136, display: "flex", justifyContent: "center" }}>
                  <OdemeBadge durum={group.odemeDurumu} />
                </div>

                {/* Yazdır (seçili varsa) + Faturalandır */}
                <div
                  style={{ display: "flex", alignItems: "center", gap: 6, flexShrink: 0 }}
                  onClick={e => e.stopPropagation()}
                >
                  {isOpen && groupSelectedIds(group.numuneler).length > 0 && (
                    <div style={{ position: "relative" }}>
                      <button
                        className={styles.editBtn}
                        style={{ color: "var(--color-accent)", borderColor: "var(--color-accent)" }}
                        title="Rapor Yazdır"
                        onClick={() => setPrintMenuEvrak(prev => prev === group.evrakNo ? null : group.evrakNo)}
                      >
                        <svg viewBox="0 0 20 20" fill="currentColor" width="13" height="13">
                          <path fillRule="evenodd" d="M5 4v3H4a2 2 0 0 0-2 2v5a2 2 0 0 0 2 2h1v1a1 1 0 0 0 1 1h8a1 1 0 0 0 1-1v-1h1a2 2 0 0 0 2-2V9a2 2 0 0 0-2-2h-1V4a1 1 0 0 0-1-1H6a1 1 0 0 0-1 1Zm2 0h6v3H7V4Zm-1 9v-2h8v2H6Zm8 2H6v-1h8v1Z" clipRule="evenodd" />
                        </svg>
                      </button>
                      {printMenuEvrak === group.evrakNo && (
                        <div style={{
                          position: "absolute", right: 0, top: "calc(100% + 4px)", zIndex: 400,
                          background: "var(--color-surface)", border: "1px solid var(--color-border)",
                          borderRadius: 8, boxShadow: "0 4px 16px rgba(0,0,0,0.12)",
                          minWidth: 140, overflow: "hidden",
                        }}>
                          {([["tr", "Türkçe"], ["en", "İngilizce"]] as const).map(([lang, label]) => (
                            <button
                              key={lang}
                              type="button"
                              onClick={() => handlePrint(groupSelectedIds(group.numuneler), lang)}
                              style={{
                                display: "block", width: "100%", textAlign: "left",
                                padding: "9px 14px", border: "none", background: "transparent",
                                fontSize: "0.8125rem", cursor: "pointer", color: "var(--color-text-primary)",
                              }}
                              onMouseEnter={e => (e.currentTarget.style.background = "var(--color-surface-2)")}
                              onMouseLeave={e => (e.currentTarget.style.background = "transparent")}
                            >
                              {label}
                            </button>
                          ))}
                        </div>
                      )}
                    </div>
                  )}
                  <button
                    className={styles.editBtn}
                    disabled={isFaturali(group.odemeDurumu)}
                    title={isFaturali(group.odemeDurumu) ? "Fatura kesilmiş" : "Faturalandır"}
                    onClick={() => {
                      // TODO: router.push(`/musteriler/proforma-listesi?evrakNo=${group.evrakNo}`)
                    }}
                    style={isFaturali(group.odemeDurumu)
                      ? { opacity: 0.25, cursor: "not-allowed" }
                      : { color: "#248a3d", borderColor: "#34c75940" }
                    }
                  >
                    <svg viewBox="0 0 20 20" fill="currentColor" width="13" height="13">
                      <path fillRule="evenodd" d="M4 4a2 2 0 0 0-2 2v8a2 2 0 0 0 2 2h12a2 2 0 0 0 2-2V6a2 2 0 0 0-2-2H4Zm0 2h12v8H4V6Zm3 5a1 1 0 0 1 1-1h4a1 1 0 1 1 0 2H8a1 1 0 0 1-1-1Zm1-3a1 1 0 0 0 0 2h2a1 1 0 0 0 0-2H8Z" clipRule="evenodd" />
                    </svg>
                  </button>
                </div>
              </div>

              {/* ── Açılır numune listesi ── */}
              {isOpen && (
                <div style={{ background: "var(--color-surface-2)", borderTop: "1px solid var(--color-border-light)" }}>
                  {group.numuneler.length === 0 ? (
                    <div style={{ padding: "12px 20px 12px 52px", fontSize: "0.8rem", color: "var(--color-text-tertiary)" }}>
                      Numune bulunamadı.
                    </div>
                  ) : (
                    <table style={{ width: "100%", borderCollapse: "collapse", fontSize: "0.82rem", tableLayout: "fixed" }}>
                      <colgroup>
                        <col style={{ width: 40 }} />
                        <col style={{ width: 150 }} />
                        <col />
                        <col style={{ width: 130 }} />
                        <col style={{ width: 170 }} />
                        <col style={{ width: 44 }} />
                      </colgroup>
                      <thead>
                        <tr style={{
                          background: "var(--color-surface)",
                          borderBottom: "2px solid var(--color-border)",
                        }}>
                          <th style={{ padding: "6px 6px 6px 16px" }} />
                          {["Rapor No", "Numune Adı", "Rapor Durumu", "Grup / Tür", ""].map((h, i) => (
                            <th key={i} style={{
                              padding: "6px 12px",
                              textAlign: "left", fontWeight: 700,
                              fontSize: "0.68rem", textTransform: "uppercase", letterSpacing: "0.07em",
                              color: "var(--color-text-secondary)",
                              whiteSpace: "nowrap",
                            }}>{h}</th>
                          ))}
                        </tr>
                      </thead>
                      <tbody>
                        {group.numuneler.map((n, ni) => (
                          <tr
                            key={n.ID}
                            style={{
                              borderBottom: ni < group.numuneler.length - 1
                                ? "1px solid var(--color-border-light)"
                                : "none",
                              background: selectedIds.has(n.ID) ? "var(--color-accent-light)" : "transparent",
                            }}
                          >
                            <td style={{ padding: "9px 6px 9px 16px", verticalAlign: "middle" }}>
                              <input
                                type="checkbox"
                                checked={selectedIds.has(n.ID)}
                                onChange={() => toggleSelect(n.ID)}
                                style={{ cursor: "pointer", width: 14, height: 14, accentColor: "var(--color-accent)" }}
                              />
                            </td>
                            <td style={{ padding: "9px 12px", whiteSpace: "nowrap" }}>
                              <a
                                href={`/laboratuvar/numune-form/${n.ID}`}
                                target="_blank"
                                rel="noopener noreferrer"
                                style={{
                                  fontWeight: 600, color: "var(--color-accent)",
                                  fontVariantNumeric: "tabular-nums",
                                  textDecoration: "none",
                                }}
                                onMouseEnter={e => (e.currentTarget.style.textDecoration = "underline")}
                                onMouseLeave={e => (e.currentTarget.style.textDecoration = "none")}
                              >
                                {n.RaporNo}
                              </a>
                            </td>
                            <td style={{ padding: "9px 12px", color: "var(--color-text-primary)", fontWeight: 500 }}>
                              {n.Numune_Adi}
                            </td>
                            <td style={{ padding: "9px 12px" }}>
                              <span style={{
                                display: "inline-block", padding: "2px 9px", borderRadius: 10,
                                fontSize: "0.72rem", fontWeight: 600,
                                background: "#ff950018", color: "#c06800",
                              }}>Devam Ediyor</span>
                            </td>
                            <td style={{ padding: "9px 12px", color: "var(--color-text-secondary)" }}>
                              {[n.Grup, n.Tur].filter(Boolean).join(" / ") || "—"}
                            </td>
                            <td style={{ padding: "9px 8px" }}>
                              <button
                                className={styles.editBtn} title="Pasife Al"
                                style={{ color: "#ff3b30" }}
                                onClick={() => setDeleteId(n.ID)}
                              >
                                <svg viewBox="0 0 20 20" fill="currentColor" width="13" height="13">
                                  <path fillRule="evenodd" d="M8.75 1A2.75 2.75 0 0 0 6 3.75v.443c-.795.077-1.584.176-2.365.298a.75.75 0 1 0 .23 1.482l.149-.022.841 10.518A2.75 2.75 0 0 0 7.596 19h4.807a2.75 2.75 0 0 0 2.742-2.53l.841-10.52.149.023a.75.75 0 0 0 .23-1.482A41.03 41.03 0 0 0 14 4.193V3.75A2.75 2.75 0 0 0 11.25 1h-2.5ZM10 4c.84 0 1.673.025 2.5.075V3.75c0-.69-.56-1.25-1.25-1.25h-2.5c-.69 0-1.25.56-1.25 1.25v.325C8.327 4.025 9.16 4 10 4ZM8.58 7.72a.75.75 0 0 0-1.5.06l.3 7.5a.75.75 0 1 0 1.5-.06l-.3-7.5Zm4.34.06a.75.75 0 1 0-1.5-.06l-.3 7.5a.75.75 0 1 0 1.5.06l.3-7.5Z" clipRule="evenodd" />
                                </svg>
                              </button>
                            </td>
                          </tr>
                        ))}
                      </tbody>
                    </table>
                  )}
                </div>
              )}
            </div>
          );
        })}

        {/* ── Sayfalama ── */}
        {!loading && totalPages > 1 && (
          <div className={styles.pagination}>
            <button className={styles.pageBtn} onClick={() => goTo(page - 1)} disabled={page === 1 || transitioning}>‹</button>
            {pageNums().map((n, i) =>
              n === "…"
                ? <span key={`d${i}`} className={styles.pageDots}>…</span>
                : <button key={n}
                    className={`${styles.pageBtn} ${page === n ? styles.pageBtnActive : ""}`}
                    disabled={transitioning}
                    onClick={() => goTo(n as number)}
                  >{n}</button>
            )}
            <button className={styles.pageBtn} onClick={() => goTo(page + 1)} disabled={page === totalPages || transitioning}>›</button>
            <span className={styles.pageInfo}>{total} evrak</span>
          </div>
        )}
      </div>

      {/* ── PASİFE AL ONAY ── */}
      {deleteId !== null && (
        <div className={styles.modalOverlay} onClick={() => setDeleteId(null)}>
          <div className={styles.modal} style={{ maxWidth: 380 }} onClick={e => e.stopPropagation()}>
            <div className={styles.modalHeader}>
              <h2>Pasife Al</h2>
              <button className={styles.modalClose} onClick={() => setDeleteId(null)}>
                <svg viewBox="0 0 20 20" fill="currentColor" width="14" height="14">
                  <path d="M6.28 5.22a.75.75 0 0 0-1.06 1.06L8.94 10l-3.72 3.72a.75.75 0 1 0 1.06 1.06L10 11.06l3.72 3.72a.75.75 0 1 0 1.06-1.06L11.06 10l3.72-3.72a.75.75 0 0 0-1.06-1.06L10 8.94 6.28 5.22Z" />
                </svg>
              </button>
            </div>
            <div className={styles.modalBody}>
              <p className={styles.deleteWarning}>
                Bu numune pasife alınacak ve aktif listeden kaldırılacak. Devam etmek istiyor musunuz?
              </p>
            </div>
            <div className={styles.modalFooter}>
              <button className={styles.cancelBtn} onClick={() => setDeleteId(null)} disabled={deleting}>İptal</button>
              <button className={styles.deleteBtnPrimary} onClick={handleDelete} disabled={deleting}>
                {deleting ? <span className={styles.loader} /> : "Pasife Al"}
              </button>
            </div>
          </div>
        </div>
      )}
    </>
  );
}

