"use client";

import { useRef, useState } from "react";
import * as XLSX from "xlsx";
import styles from "@/app/styles/table.module.css";
import type { FormulRow } from "./numuneFormTypes";

function newKey() {
  return `f-${Date.now()}-${Math.random().toString(36).slice(2, 9)}`;
}

interface Props {
  rows: FormulRow[];
  onChange: (rows: FormulRow[]) => void;
}

export default function Tab3Formul({ rows, onChange }: Props) {
  const [inputText, setInputText] = useState("");
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");
  const fileRef = useRef<HTMLInputElement>(null);

  const appendRows = (list: { INCIName: string; Miktar: string }[]) => {
    if (list.length === 0) return;
    onChange([
      ...rows,
      ...list.map(r => ({
        key: newKey(),
        HammaddeID: null,
        INCIName: r.INCIName,
        Miktar: r.Miktar,
        DaP: "",
        Noael: "",
      })),
    ]);
  };

  const handlePaste = () => {
    setError("");
    if (!inputText.trim()) {
      setError("Önce formül satırlarını yapıştırın (INCI ve miktar, tab veya çoklu boşluk ile ayrılmış).");
      return;
    }
    const lines = inputText.split("\n").filter(l => l.trim());
    const parsed = lines.map(l => {
      const parts = l.split("\t");
      if (parts.length >= 2) {
        return { INCIName: parts[0].trim(), Miktar: (parts[1] || "0").trim().replace(",", ".") };
      }
      const fb = l.split(/\s\s+/);
      if (fb.length >= 2) {
        return { INCIName: fb[0].trim(), Miktar: fb[1].trim().replace(",", ".") };
      }
      return null;
    }).filter((x): x is { INCIName: string; Miktar: string } => !!x?.INCIName);

    if (parsed.length === 0) {
      setError("Satır ayrıştırılamadı.");
      return;
    }
    appendRows(parsed);
    setInputText("");
  };

  const handleFile = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    setError("");
    const reader = new FileReader();
    reader.onload = evt => {
      try {
        const bstr = evt.target?.result;
        const wb = XLSX.read(bstr, { type: "binary" });
        const ws = wb.Sheets[wb.SheetNames[0]];
        const data = XLSX.utils.sheet_to_json(ws) as Record<string, unknown>[];
        const items = data.map(row => ({
          INCIName: String(row["INCI İsmi"] ?? row["INCI ismi"] ?? row["INCI"] ?? "").trim(),
          Miktar: String(row["Üst Değer(%)"] ?? row["Üst değer(%)"] ?? row["Miktar"] ?? "0").replace(",", "."),
        })).filter(i => i.INCIName);
        if (items.length === 0) {
          setError("Excel'de 'INCI İsmi' ve 'Üst Değer(%)' (veya Miktar) sütunları bulunamadı.");
          return;
        }
        appendRows(items);
      } catch {
        setError("Dosya okunamadı.");
      }
    };
    reader.readAsBinaryString(file);
    e.target.value = "";
  };

  const matchAll = async () => {
    if (rows.length === 0) return;
    setLoading(true);
    setError("");
    try {
      const items = rows.map(r => ({ name: r.INCIName, amount: r.Miktar || "0" }));
      const res = await fetch("/api/formul-kontrol/match", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ items }),
      });
      if (!res.ok) throw new Error("Eşleştirme başarısız");
      const json = (await res.json()) as { INCIName: string | null; inputName: string; inputAmount: string }[];
      const next = rows.map((r, i) => {
        const m = json[i];
        if (!m) return r;
        return {
          ...r,
          INCIName: m.INCIName || m.inputName || r.INCIName,
          Miktar: m.inputAmount || r.Miktar,
        };
      });
      onChange(next);
    } catch (e: unknown) {
      setError(e instanceof Error ? e.message : "Hata");
    } finally {
      setLoading(false);
    }
  };

  const update = (key: string, patch: Partial<FormulRow>) =>
    onChange(rows.map(r => (r.key === key ? { ...r, ...patch } : r)));

  const remove = (key: string) => onChange(rows.filter(r => r.key !== key));

  return (
    <div style={{ padding: "20px 24px" }}>
      <p style={{ fontSize: "0.8425rem", color: "var(--color-text-secondary)", marginBottom: 16, lineHeight: 1.55 }}>
        Formül kontrol sayfasındaki gibi yapıştırma veya Excel şablonu kullanın. İsterseniz satırları ekledikten sonra
        INCI isimlerini veritabanı ile eşleştirin.
      </p>

      {error && <div className={styles.formError} style={{ marginBottom: 12 }}>{error}</div>}

      <div className={styles.formGroup} style={{ marginBottom: 12 }}>
        <label>Yapıştır (satır başına: INCI [tab] miktar)</label>
        <textarea
          rows={5}
          style={{ width: "100%", resize: "vertical", fontFamily: "ui-monospace, monospace", fontSize: "0.8rem" }}
          value={inputText}
          onChange={e => setInputText(e.target.value)}
          placeholder={"GLYCERIN\t5\nAQUA\t80"}
        />
      </div>
      <div style={{ display: "flex", gap: 10, flexWrap: "wrap", marginBottom: 20 }}>
        <button type="button" className={styles.saveBtn} onClick={handlePaste}>Satırları ekle</button>
        <input ref={fileRef} type="file" accept=".xlsx,.xls" style={{ display: "none" }} onChange={handleFile} />
        <button type="button" className={styles.cancelBtn} onClick={() => fileRef.current?.click()}>
          Excel seç
        </button>
        <button type="button" className={styles.cancelBtn} onClick={() => void matchAll()} disabled={rows.length === 0 || loading}>
          {loading ? "Eşleştiriliyor…" : "Tümünü formül kontrol ile eşleştir"}
        </button>
      </div>

      {rows.length === 0 ? (
        <div className={styles.empty} style={{ padding: 24 }}>Formül satırı yok.</div>
      ) : (
        <div className={styles.tableWrapper}>
          <table className={styles.table}>
            <thead>
              <tr>
                <th>INCI / Hammadde</th>
                <th style={{ width: 100 }}>Miktar</th>
                <th style={{ width: 90 }}>DaP</th>
                <th style={{ width: 90 }}>Noael</th>
                <th style={{ width: 48 }} />
              </tr>
            </thead>
            <tbody>
              {rows.map(r => (
                <tr key={r.key}>
                  <td>
                    <input style={{ width: "100%" }} value={r.INCIName} onChange={e => update(r.key, { INCIName: e.target.value })} />
                  </td>
                  <td>
                    <input style={{ width: "100%" }} value={r.Miktar} onChange={e => update(r.key, { Miktar: e.target.value })} />
                  </td>
                  <td>
                    <input style={{ width: "100%" }} value={r.DaP} onChange={e => update(r.key, { DaP: e.target.value })} />
                  </td>
                  <td>
                    <input style={{ width: "100%" }} value={r.Noael} onChange={e => update(r.key, { Noael: e.target.value })} />
                  </td>
                  <td>
                    <button type="button" className={styles.editBtn} style={{ color: "var(--color-danger)" }} onClick={() => remove(r.key)}>✕</button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}
    </div>
  );
}

