  const addFromDate = (tarihStr: string, sure: number) => {
    const base = tarihStr ? new Date(tarihStr + "T12:00:00") : new Date();
    base.setDate(base.getDate() + Math.max(0, sure));
    return base.toISOString().split("T")[0]!;
