    UGDTip_ID: null,
    Hedef_Grup: "Yetişkinler",
    hizmetler: [],
    FotoFile: null,
    FotoPreview: "",
    open: true,
    saving: false,
    saved: false,
    error: "",
    ...partial,
  };
}

function normalizePartialDate(v: string): string | null {
  if (!v) return null;
  const parts = v.split("-");
  if (parts.length === 1) return `${parts[0]}-01-01`;
