"use client";

import { useState, useCallback, useRef, useEffect } from "react";
import Link from "next/link";
import yn from "./yeni-numune.module.css";
import type { HizmetRow, LookupData } from "../numune-form/numuneFormTypes";

// ── Tipler ────────────────────────────────────────────────
