      )}

      {mode === "paket" && (
        <div style={{ background: "var(--color-bg)", border: "1px solid var(--color-border)", borderRadius: 8, padding: 10, marginBottom: 10 }}>
          {paketLoading ? <p style={{ fontSize: "0.78rem", color: "var(--color-text-tertiary)" }}>Yükleniyor…</p>
