            </div>
            <div className={yn.evrakGrid2}>
              <FirmaSearch label="Firma" value={evrak.Firma_ID} displayValue={evrak.FirmaAd} onChange={(id, ad) => patchEvrak({ Firma_ID: id, FirmaAd: ad })} placeholder="Firma adı…" />
