5	export const authOptions: NextAuthOptions = {
6	  providers: [
7	    CredentialsProvider({
8	      name: "Tesis Girişi",
9	      credentials: {
10	        username: { label: "Kullanıcı Adı", type: "text" },
11	        password: { label: "Şifre", type: "password" },
12	      },
13	      async authorize(credentials) {
14	        if (!credentials?.username || !credentials?.password) {
15	          throw new Error("Lütfen kullanıcı adı ve şifrenizi girin.");
16	        }
17	
18	        try {
19	          const pool = await sql;
20	
21	          // Kolon listesini dinamik oku
22	          const colsResult = await pool.request().query(`
23	            SELECT COLUMN_NAME FROM INFORMATION_SCHEMA.COLUMNS
24	            WHERE TABLE_NAME = 'RootKullanici'
25	          `);
26	          const cols = colsResult.recordset.map((r: any) => r.COLUMN_NAME as string);
27	
28	          const passwordCol = cols.find((c) =>
29	            ["Sifre", "Parola", "Password", "sifre", "password", "parola", "UserPassword", "UserParola"].includes(c)
30	          );
31	          const usernameCol = cols.find((c) =>
32	            ["KullaniciAdi", "Kadi", "UserName", "Username", "kullanici_adi", "Login", "kadi"].includes(c)
33	          );
34	          const emailCol = cols.find((c) => ["Email", "email", "EMail", "Eposta"].includes(c));
35	          const idCol = cols.find((c) => ["Id", "ID", "id", "KullaniciId"].includes(c));
36	          
37	          // AdSoyad yoksa Ad ve Soyad'ı birleştir
38	          const nameCol = cols.find((c) => ["AdSoyad", "FullName", "Name", "Adi"].includes(c));
39	          const firstNameCol = cols.find((c) => ["Ad", "FirstName", "Firstname"].includes(c));
40	          const lastNameCol = cols.find((c) => ["Soyad", "LastName", "Lastname"].includes(c));
41	          
42	          const birimCol = cols.find((c) => ["BirimID", "BirimId", "birimid", "Birim"].includes(c));
43	
44	          if (!passwordCol || !usernameCol) {
45	            throw new Error(`Tablo yapısı okunamadı. Eksik kolonlar var: ${cols.join(", ")}`);
46	          }
47	
48	          const whereClause = emailCol
49	            ? `(${usernameCol} = @username OR ${emailCol} = @username)`
50	            : `${usernameCol} = @username`;
51	
52	          const result = await pool.request()
53	            .input("username", credentials.username)
54	            .input("password", credentials.password)
55	            .query(`
56	              SELECT TOP 1 * FROM RootKullanici
57	              WHERE ${whereClause} AND ${passwordCol} = @password
58	            `);
59	
60	          const user = result.recordset[0];
61	
62	          if (user) {
63	            // İsim oluşturma
64	            let displayName = user[usernameCol];
65	            if (nameCol) {
66	              displayName = user[nameCol];
67	            } else if (firstNameCol && lastNameCol) {
68	              displayName = `${user[firstNameCol]} ${user[lastNameCol]}`.trim();
69	            } else if (firstNameCol) {
70	              displayName = user[firstNameCol];
71	            }
72	
73	            return {
74	              id: idCol ? String(user[idCol]) : user[usernameCol],
75	              name: displayName,
76	              email: emailCol ? user[emailCol] : null,
77	              birimId: birimCol ? (Number(user[birimCol]) || 0) : 0,
78	            };
79	          } else {
80	            throw new Error("Hatalı kullanıcı adı veya şifre.");
81	          }
82	        } catch (error: any) {
83	          console.error("Auth Hatası:", error);
84	          throw new Error(error.message || "Giriş işlemi sırasında sunucu hatası oluştu.");
85	        }
86	      },
87	    }),
88	  ],
89	  callbacks: {
90	    async jwt({ token, user }) {
91	      if (user) {
92	        token.birimId = (user as any).birimId ?? 0;
93	        token.userId  = user.id; // DB'deki ID (string)
94	      }
95	      return token;
96	    },
97	    async session({ session, token }) {
98	      if (session.user) {
99	        session.user.birimId = token.birimId ?? 0;
100	        session.user.userId  = token.userId as string;
101	      }
102	      return session;
103	    },
104	  },
